import { QueryResult } from '../types';
import { INITIAL_SQL } from '../constants';

// We access alasql from the window object as it's loaded via CDN script
declare global {
    interface Window {
        alasql: any;
    }
}

let isInitialized = false;

export const initDB = () => {
    if (isInitialized) return;
    if (window.alasql) {
        try {
            // Create in-memory database
            window.alasql('CREATE DATABASE IF NOT EXISTS sql_game');
            window.alasql('USE sql_game');

            // Check if tables exist, if not run initial SQL
            // For simplicity in this demo, we drop and recreate on refresh 
            // In a real app with persistence we would check existence.
            // Since alasql is in-memory only (unless using localstorage plugin), 
            // we re-seed every reload but keep Game Progress (current case) in localStorage.

            // Split by semicolon and run each
            const statements = INITIAL_SQL.split(';').filter(stmt => stmt.trim().length > 0);
            statements.forEach(stmt => {
                window.alasql(stmt);
            });

            isInitialized = true;
            console.log("Database initialized.");
        } catch (e) {
            console.error("Failed to initialize DB", e);
        }
    }
};

export const runQuery = (sql: string): QueryResult => {
    const startTime = performance.now();
    try {
        if (!sql.trim()) return { columns: [], data: [] };

        // Basic security check (client side, but still good practice)
        const forbidden = ['DROP', 'DELETE', 'UPDATE', 'INSERT', 'ALTER'];
        const upperSql = sql.toUpperCase();
        if (forbidden.some(word => upperSql.includes(word))) {
             return {
                columns: [],
                data: [],
                error: "PERMISSION DENIED: Read-only access authorized for this terminal."
            };
        }

        const data = window.alasql(sql);
        const executionTime = performance.now() - startTime;

        if (!Array.isArray(data)) {
            // Some commands like USE return something else, return empty for display
            return { columns: [], data: [], executionTime };
        }

        if (data.length === 0) {
            return { columns: [], data: [], executionTime };
        }

        const columns = Object.keys(data[0]);
        return {
            columns,
            data,
            executionTime
        };

    } catch (error: any) {
        return {
            columns: [],
            data: [],
            error: error.message || "Syntax Error",
            executionTime: performance.now() - startTime
        };
    }
};

import { GoogleGenAI, Type } from "@google/genai";

// Ensure API key is present
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// 1. Fast Hints (Gemini 2.5 Flash Lite)
// Used when user specifically asks for a hint about the case
export const getFastHint = async (userQuery: string, currentContext: string): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-lite-latest',
            contents: `
                You are a senior detective's AI assistant. 
                Context: ${currentContext}
                User Question: ${userQuery}

                Provide a short, cryptic but helpful hint. Do not give the exact answer. 
                Keep it under 2 sentences.
            `,
            config: {
                systemInstruction: "You are a noir-style detective assistant.",
                temperature: 0.7,
            }
        });
        return response.text || "Connection to HQ interrupted...";
    } catch (error) {
        console.error("Gemini Hint Error", error);
        return "System offline. Consult your field manual.";
    }
};

// 2. Syntax/Knowledge Lookup (Search Grounding)
// Used when user asks about SQL syntax or general knowledge
export const getKnowledgeHelp = async (query: string): Promise<{text: string, sources: string[]}> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: query,
            config: {
                tools: [{ googleSearch: {} }],
                systemInstruction: "You are a database administrator helper. Explain SQL concepts clearly."
            }
        });

        const text = response.text || "No data found.";
        const sources: string[] = [];

        if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
            response.candidates[0].groundingMetadata.groundingChunks.forEach(chunk => {
                if (chunk.web?.uri) {
                    sources.push(chunk.web.uri);
                }
            });
        }

        return { text, sources };
    } catch (error) {
        console.error("Gemini Search Error", error);
        return { text: "Network failure during knowledge retrieval.", sources: [] };
    }
};

// 3. Complex Reasoning / Chief of Police (Gemini 3 Pro with Thinking)
// Used when user submits an answer to verify reasoning or provide a detailed case closed report
export const submitCaseReview = async (
    caseDetails: string, 
    userAnswer: string, 
    queryHistory: string[]
): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: `
                The user is playing a detective game.
                Case Details: ${caseDetails}
                User Answer: ${userAnswer}
                User's Query History: ${JSON.stringify(queryHistory)}

                Role: You are the Chief of Police. 

                Task:
                1. Determine if the User Answer matches the case solution (or is logically correct based on the data).
                2. If correct, congratulate them with a stern but proud tone. Mention specifically how their queries helped.
                3. If incorrect, scold them gently and explain where the logic might have failed based on their queries.
            `,
            config: {
                thinkingConfig: { thinkingBudget: 32768 } // Max thinking for deep analysis
            }
        });

        return response.text || "Report generation failed.";
    } catch (error) {
        console.error("Gemini Thinking Error", error);
        return "The Chief is busy. Try again later.";
    }
};

