import React, { useState, useEffect } from 'react';

interface SqlEditorProps {
    onRun: (sql: string) => void;
    isRunning: boolean;
}

const SqlEditor: React.FC<SqlEditorProps> = ({ onRun, isRunning }) => {
    const [sql, setSql] = useState('');

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            onRun(sql);
        }
    };

    return (
        <div className="flex flex-col h-1/2 min-h-[300px] border-b border-terminal-border">
            <div className="bg-terminal-border/20 px-4 py-2 flex justify-between items-center border-b border-terminal-border">
                <span className="text-xs uppercase text-terminal-text font-bold tracking-widest">Query Console</span>
                <span className="text-xs text-terminal-text opacity-50">CTRL+ENTER to run</span>
            </div>
            <textarea
                value={sql}
                onChange={(e) => setSql(e.target.value)}
                onKeyDown={handleKeyDown}
                className="flex-1 bg-[#0D1117] text-terminal-text p-4 font-mono text-base resize-none focus:outline-none focus:ring-1 focus:ring-terminal-border"
                placeholder="-- Type your SQL query here...
SELECT * FROM crime_scene_report LIMIT 5;"
                spellCheck={false}
            />
            <div className="p-2 bg-terminal-bg flex justify-end">
                <button 
                    onClick={() => onRun(sql)}
                    disabled={isRunning}
                    className={`
                        px-6 py-2 bg-terminal-green text-black font-bold font-mono text-sm rounded hover:bg-green-400 transition-colors
                        ${isRunning ? 'opacity-50 cursor-not-allowed' : ''}
                    `}
                >
                    {isRunning ? 'EXECUTING...' : 'RUN QUERY'}
                </button>
            </div>
        </div>
    );
};

export default SqlEditor;

import React from 'react';
import { QueryResult } from '../types';

interface ResultsTableProps {
    result: QueryResult | null;
}

const ResultsTable: React.FC<ResultsTableProps> = ({ result }) => {
    if (!result) {
        return (
            <div className="h-1/2 flex items-center justify-center text-terminal-text opacity-30 font-mono">
                NO RESULTS TO DISPLAY
            </div>
        );
    }

    if (result.error) {
        return (
            <div className="h-1/2 p-4 font-mono">
                <div className="text-red-500 font-bold mb-2">ERROR:</div>
                <div className="text-red-400">{result.error}</div>
            </div>
        );
    }

    if (result.data.length === 0 && result.columns.length === 0) {
        return (
             <div className="h-1/2 p-4 font-mono text-terminal-green">
                Query executed successfully. No rows returned.
                <div className="text-xs opacity-50 mt-1">{result.executionTime?.toFixed(2)}ms</div>
            </div>
        );
    }

    return (
        <div className="h-1/2 overflow-auto bg-[#0D1117] flex flex-col">
            <div className="px-4 py-2 bg-terminal-border/20 border-b border-terminal-border flex justify-between items-center sticky top-0">
                <span className="text-xs uppercase text-terminal-text font-bold tracking-widest">
                    Result Grid ({result.data.length} rows)
                </span>
                <span className="text-xs font-mono text-terminal-text opacity-50">
                    {result.executionTime?.toFixed(2)}ms
                </span>
            </div>
            <div className="flex-1 overflow-auto">
                <table className="w-full text-left border-collapse font-mono text-sm">
                    <thead className="sticky top-0 bg-terminal-bg z-10">
                        <tr>
                            {result.columns.map((col, idx) => (
                                <th key={idx} className="p-3 border-b border-terminal-border text-terminal-blue font-bold whitespace-nowrap">
                                    {col}
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {result.data.map((row, rowIdx) => (
                            <tr key={rowIdx} className="hover:bg-terminal-border/10 transition-colors group">
                                {result.columns.map((col, colIdx) => (
                                    <td key={colIdx} className="p-3 border-b border-terminal-border/50 text-terminal-text whitespace-nowrap max-w-xs overflow-hidden text-ellipsis">
                                        {row[col] === null ? <span className="text-red-900 italic">NULL</span> : String(row[col])}
                                    </td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default ResultsTable;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Case } from '../types';
import { getFastHint, getKnowledgeHelp, submitCaseReview } from '../services/geminiService';

interface ChatAssistantProps {
    currentCase: Case;
    queryHistory: string[];
    onCaseSolved: () => void;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentCase, queryHistory, onCaseSolved }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([
        { id: '1', role: 'model', text: `Detective, I'm your AI partner. I can help with SQL syntax or give you clues. Type "solve: [name]" to submit a suspect.`, timestamp: Date.now() }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [messages]);

    const handleSend = async () => {
        if (!input.trim() || isLoading) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            text: input,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsLoading(true);

        try {
            // Determine intent
            const lowerInput = input.toLowerCase();
            let aiResponseText = '';

            if (lowerInput.startsWith('solve:')) {
                // SUBMIT ANSWER -> GEMINI 3 PRO (Thinking)
                const answer = input.substring(6).trim();

                // Add a placeholder for thinking
                setMessages(prev => [...prev, {
                    id: 'thinking',
                    role: 'model',
                    text: "Analyzing case files and cross-referencing evidence...",
                    timestamp: Date.now(),
                    isThinking: true
                }]);

                const review = await submitCaseReview(
                    JSON.stringify(currentCase),
                    answer,
                    queryHistory
                );

                // Check simple exact match for game logic trigger, but let AI explain it
                const isCorrect = answer.toLowerCase() === currentCase.expectedAnswer.toLowerCase();

                setMessages(prev => prev.filter(m => m.id !== 'thinking')); // Remove thinking placeholder

                aiResponseText = review;

                if (isCorrect) {
                     // Wait a bit then trigger solved
                     setTimeout(onCaseSolved, 3000);
                }

            } else if (lowerInput.includes('how to') || lowerInput.includes('syntax') || lowerInput.includes('what is')) {
                // SQL HELP -> GEMINI 3 FLASH (Search Grounding)
                const { text, sources } = await getKnowledgeHelp(input);
                aiResponseText = text;
                if (sources.length > 0) {
                    aiResponseText += `\n\nSources:\n${sources.map(s => `- ${s}`).join('\n')}`;
                }

            } else {
                // HINT -> GEMINI 2.5 FLASH LITE (Fast)
                const hint = await getFastHint(input, currentCase.briefing);
                aiResponseText = hint;
            }

            const aiMsg: ChatMessage = {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: aiResponseText,
                timestamp: Date.now()
            };
            setMessages(prev => [...prev, aiMsg]);

        } catch (error) {
            setMessages(prev => [...prev, {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: "Communication error. Try again.",
                timestamp: Date.now()
            }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex flex-col h-full bg-terminal-bg border-l border-terminal-border w-96">
            <div className="p-4 border-b border-terminal-border bg-black/20">
                <h2 className="text-terminal-blue font-bold uppercase text-xs tracking-widest">AI Field Partner</h2>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div 
                            className={`
                                max-w-[90%] p-3 rounded-lg text-sm font-mono whitespace-pre-wrap
                                ${msg.role === 'user' 
                                    ? 'bg-terminal-blue/20 text-terminal-blue border border-terminal-blue/30 rounded-br-none' 
                                    : 'bg-terminal-border/40 text-terminal-text border border-terminal-border rounded-bl-none'}
                                ${msg.isThinking ? 'animate-pulse' : ''}
                            `}
                        >
                            {msg.text}
                        </div>
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>

            <div className="p-4 border-t border-terminal-border bg-black/20">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder="Ask for hint or 'solve: [name]'"
                        className="flex-1 bg-terminal-bg border border-terminal-border rounded px-3 py-2 text-sm text-terminal-text focus:outline-none focus:border-terminal-blue font-mono"
                        disabled={isLoading}
                    />
                    <button 
                        onClick={handleSend}
                        disabled={isLoading}
                        className="p-2 bg-terminal-blue/20 text-terminal-blue border border-terminal-blue/30 rounded hover:bg-terminal-blue/30 disabled:opacity-50"
                    >
                        ➤
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ChatAssistant;

import React, { useEffect, useState } from 'react';
import Sidebar from './components/Sidebar';
import SqlEditor from './components/SqlEditor';
import ResultsTable from './components/ResultsTable';
import ChatAssistant from './components/ChatAssistant';
import { CASES } from './constants';
import { runQuery, initDB } from './services/dbService';
import { QueryResult } from './types';

function App() {
  const [currentCaseIndex, setCurrentCaseIndex] = useState(0);
  const [queryResult, setQueryResult] = useState<QueryResult | null>(null);
  const [queryHistory, setQueryHistory] = useState<string[]>([]);
  const [isExecuting, setIsExecuting] = useState(false);
  const [completedCases, setCompletedCases] = useState<string[]>([]);
  const [gameState, setGameState] = useState<'LOADING' | 'READY' | 'SOLVED_ANIMATION'>('LOADING');

  // Persistence Load
  useEffect(() => {
    initDB();

    const savedCase = localStorage.getItem('sqlpd_currentCase');
    const savedCompleted = localStorage.getItem('sqlpd_completed');

    if (savedCase) setCurrentCaseIndex(parseInt(savedCase));
    if (savedCompleted) setCompletedCases(JSON.parse(savedCompleted));

    setGameState('READY');
  }, []);

  // Persistence Save
  useEffect(() => {
    localStorage.setItem('sqlpd_currentCase', currentCaseIndex.toString());
    localStorage.setItem('sqlpd_completed', JSON.stringify(completedCases));
  }, [currentCaseIndex, completedCases]);

  const currentCase = CASES[currentCaseIndex];

  const handleRunQuery = (sql: string) => {
    setIsExecuting(true);
    setQueryHistory(prev => [...prev, sql]);

    // Simulate slight network delay for realism
    setTimeout(() => {
        const result = runQuery(sql);
        setQueryResult(result);
        setIsExecuting(false);
    }, 400);
  };

  const handleCaseSolved = () => {
    setGameState('SOLVED_ANIMATION');
    if (!completedCases.includes(currentCase.id)) {
        setCompletedCases(prev => [...prev, currentCase.id]);
    }
  };

  const nextCase = () => {
    if (currentCaseIndex < CASES.length - 1) {
        setCurrentCaseIndex(prev => prev + 1);
        setQueryResult(null);
        setQueryHistory([]);
        setGameState('READY');
    }
  };

  if (gameState === 'LOADING') {
    return <div className="h-screen w-screen bg-black text-terminal-green flex items-center justify-center font-mono">INITIALIZING DATABASE CONNECTION...</div>;
  }

  if (gameState === 'SOLVED_ANIMATION') {
    return (
        <div className="h-screen w-screen bg-black flex flex-col items-center justify-center font-mono text-center p-8 space-y-6">
            <h1 className="text-6xl font-bold text-terminal-green animate-bounce">CASE CLOSED</h1>
            <p className="text-xl text-terminal-text max-w-2xl">
                Excellent work, detective. The perpetrator has been booked and the paperwork filed.
            </p>
            <div className="flex gap-4">
                {currentCaseIndex < CASES.length - 1 ? (
                    <button 
                        onClick={nextCase}
                        className="px-8 py-3 bg-terminal-blue text-black font-bold rounded hover:scale-105 transition-transform"
                    >
                        NEXT CASE
                    </button>
                ) : (
                    <div className="text-yellow-500 text-xl">
                        ALL CURRENT CASES CLEARED. YOU ARE A MASTER DETECTIVE.
                    </div>
                )}
            </div>
        </div>
    );
  }

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-[#0D1117] text-[#C9D1D9]">
      <Sidebar 
        currentCase={currentCase} 
        completedCases={completedCases}
        onCaseSelect={() => {}} // Could be implemented to review old cases
      />

      <div className="flex-1 flex flex-col min-w-0">
        {/* Case Briefing Header */}
        <div className="p-6 border-b border-terminal-border bg-black/40">
            <div className="flex justify-between items-start">
                <div>
                    <h2 className="text-2xl font-bold text-white mb-2">{currentCase.title}</h2>
                    <p className="text-terminal-text opacity-80 font-mono whitespace-pre-wrap text-sm max-w-4xl">
                        {currentCase.briefing}
                    </p>
                </div>
                <div className="bg-terminal-border/30 px-4 py-2 rounded text-right">
                    <div className="text-xs uppercase text-terminal-text opacity-50">Objective</div>
                    <div className="text-terminal-green font-bold text-sm">{currentCase.objective}</div>
                </div>
            </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col min-h-0">
            <SqlEditor onRun={handleRunQuery} isRunning={isExecuting} />
            <ResultsTable result={queryResult} />
        </div>
      </div>

      <ChatAssistant 
        currentCase={currentCase}
        queryHistory={queryHistory}
        onCaseSolved={handleCaseSolved}
      />
    </div>
  );
}

