import React, { useEffect, useState } from 'react';
import Sidebar from './components/Sidebar';
import SqlEditor from './components/SqlEditor';
import ResultsTable from './components/ResultsTable';
import ChatAssistant from './components/ChatAssistant';
import { CASES } from './constants';
import { runQuery, initDB } from './services/dbService';
import { QueryResult } from './types';
import { submitCaseReview } from './services/geminiService';

function App() {
  const [currentCaseIndex, setCurrentCaseIndex] = useState(0);
  const [queryResult, setQueryResult] = useState<QueryResult | null>(null);
  const [queryHistory, setQueryHistory] = useState<string[]>([]);
  const [isExecuting, setIsExecuting] = useState(false);
  const [completedCases, setCompletedCases] = useState<string[]>([]);
  const [gameState, setGameState] = useState<'LOADING' | 'READY' | 'CHECKING' | 'SOLVED_ANIMATION' | 'FAILED'>('LOADING');
  const [answerInput, setAnswerInput] = useState('');
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [feedback, setFeedback] = useState<string>('');

  // Persistence Load
  useEffect(() => {
    // Delay init slightly to ensure DOM is ready for heavy JS
    setTimeout(() => {
        initDB();
        const savedCase = localStorage.getItem('sqlpd_currentCase');
        const savedCompleted = localStorage.getItem('sqlpd_completed');

        // Validation to prevent crashing if we added new cases before the old saved index
        if (savedCase) {
             const idx = parseInt(savedCase);
             if (idx < CASES.length) setCurrentCaseIndex(idx);
             else setCurrentCaseIndex(0);
        }
        if (savedCompleted) setCompletedCases(JSON.parse(savedCompleted));

        setGameState('READY');
    }, 100);
  }, []);

  // Persistence Save
  useEffect(() => {
    localStorage.setItem('sqlpd_currentCase', currentCaseIndex.toString());
    localStorage.setItem('sqlpd_completed', JSON.stringify(completedCases));
  }, [currentCaseIndex, completedCases]);

  const currentCase = CASES[currentCaseIndex];

  const handleRunQuery = (sql: string) => {
    setIsExecuting(true);
    setQueryHistory(prev => [...prev, sql]);

    // Simulate slight network delay for realism
    setTimeout(() => {
        const result = runQuery(sql);
        setQueryResult(result);
        setIsExecuting(false);
    }, 400);
  };

  const handleCaseSelect = (caseId: string) => {
      const index = CASES.findIndex(c => c.id === caseId);
      if (index !== -1) {
          // Security check: ensure the user has unlocked this level
          // A user can access any level index <= their number of completed cases
          if (index <= completedCases.length) {
              setCurrentCaseIndex(index);
              setQueryResult(null);
              setQueryHistory([]);
              setAnswerInput('');
              setFeedback('');
              setGameState('READY');
              setIsSubmitModalOpen(false); // Close modal if open
          }
      }
  };

  const checkAnswer = async () => {
      setGameState('CHECKING');

      // 1. Simple Check (Exact Match)
      const isExactMatch = answerInput.toLowerCase().trim() === currentCase.expectedAnswer.toLowerCase().trim();

      // 2. AI Review for flavor text
      const review = await submitCaseReview(
          JSON.stringify(currentCase),
          answerInput,
          queryHistory
      );

      setFeedback(review);

      if (isExactMatch) {
          if (!completedCases.includes(currentCase.id)) {
              setCompletedCases(prev => [...prev, currentCase.id]);
          }
          setGameState('SOLVED_ANIMATION');
          setIsSubmitModalOpen(false);
      } else {
          setGameState('FAILED');
      }
  };

  const nextCase = () => {
    if (currentCaseIndex < CASES.length - 1) {
        setCurrentCaseIndex(prev => prev + 1);
        setQueryResult(null);
        setQueryHistory([]);
        setAnswerInput('');
        setFeedback('');
        setGameState('READY');
    }
  };

  if (gameState === 'LOADING') {
    return (
        <div className="h-screen w-screen bg-black text-terminal-green flex flex-col items-center justify-center font-mono">
            <div className="animate-pulse text-2xl mb-4">ESTABLISHING SECURE CONNECTION...</div>
            <div className="text-terminal-text opacity-50">Loading SQL City Police Database (SCPD-NET)</div>
        </div>
    );
  }

  if (gameState === 'SOLVED_ANIMATION') {
    return (
        <div className="h-screen w-screen bg-[#0D1117] flex flex-col items-center justify-center font-mono text-center p-8 space-y-6">
            <h1 className="text-6xl font-bold text-terminal-green animate-bounce">
                {currentCase.id.startsWith('academy') ? 'TRAINING COMPLETED' : 'CASE CLOSED'}
            </h1>
            <div className="bg-terminal-border/20 p-6 rounded-lg border border-terminal-green/30 max-w-2xl">
                <p className="text-lg text-terminal-text whitespace-pre-wrap">{feedback}</p>
            </div>
            <div className="flex gap-4">
                {currentCaseIndex < CASES.length - 1 ? (
                    <button 
                        onClick={nextCase}
                        className="px-8 py-3 bg-terminal-blue text-black font-bold rounded hover:scale-105 transition-transform"
                    >
                        {currentCase.id.startsWith('academy') ? 'NEXT LESSON' : 'ACCESS NEXT CASE FILE'}
                    </button>
                ) : (
                    <div className="flex flex-col items-center gap-4">
                         <div className="text-yellow-500 text-xl font-bold border border-yellow-500/50 p-4 rounded">
                            CONGRATULATIONS, DETECTIVE. <br/>
                            YOU HAVE SOLVED ALL CURRENT INVESTIGATIONS.
                        </div>
                        <button 
                            onClick={() => {
                                localStorage.clear();
                                window.location.reload();
                            }}
                            className="text-xs text-terminal-text underline hover:text-white"
                        >
                            Reset Progress
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
  }

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-[#0D1117] text-[#C9D1D9]">
      <Sidebar 
        currentCase={currentCase} 
        completedCases={completedCases}
        onCaseSelect={handleCaseSelect} 
      />

      <div className="flex-1 flex flex-col min-w-0">
        {/* Case Briefing Header */}
        <div className="p-6 border-b border-terminal-border bg-black/40">
            <div className="flex justify-between items-start">
                <div>
                    <h2 className="text-2xl font-bold text-white mb-2 flex items-center gap-2">
                        {currentCase.title}
                        {completedCases.includes(currentCase.id) && <span className="text-sm bg-green-900 text-green-300 px-2 py-0.5 rounded">SOLVED</span>}
                    </h2>
                    <p className="text-terminal-text opacity-80 font-mono whitespace-pre-wrap text-sm max-w-4xl">
                        {currentCase.briefing}
                    </p>
                </div>
                <div className="flex flex-col items-end gap-2">
                    <button 
                        onClick={() => setIsSubmitModalOpen(true)}
                        className="bg-terminal-green hover:bg-green-600 text-black font-bold px-6 py-2 rounded shadow-lg shadow-green-900/20 transition-all"
                    >
                        FILE REPORT (SOLVE)
                    </button>
                    <div className="text-xs text-terminal-text opacity-50">
                        Diff: <span className="text-terminal-blue">{currentCase.difficulty}</span>
                    </div>
                </div>
            </div>
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col min-h-0">
            <SqlEditor onRun={handleRunQuery} isRunning={isExecuting} />
            <ResultsTable result={queryResult} />
        </div>
      </div>

      <ChatAssistant 
        currentCase={currentCase}
        queryHistory={queryHistory}
        onCaseSolved={() => setIsSubmitModalOpen(true)}
      />

      {/* Submit Answer Modal */}
      {isSubmitModalOpen && (
          <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
              <div className="bg-[#161b22] border border-terminal-border w-full max-w-md rounded-lg shadow-2xl p-6 relative">
                  <button 
                    onClick={() => {
                        setIsSubmitModalOpen(false);
                        setGameState('READY');
                        setFeedback('');
                    }}
                    className="absolute top-4 right-4 text-terminal-text opacity-50 hover:opacity-100"
                  >
                      ✕
                  </button>
                  <h3 className="text-xl font-bold text-white mb-4 border-b border-terminal-border pb-2">File Final Report</h3>
                  <p className="text-sm text-terminal-text mb-4 font-mono">{currentCase.objective}</p>

                  {gameState === 'FAILED' && (
                      <div className="bg-red-900/20 border border-red-500/30 p-3 mb-4 rounded text-sm text-red-300">
                          <strong>INCORRECT:</strong> {feedback || "The evidence does not support this conclusion. Double check your queries."}
                      </div>
                  )}

                  <input 
                    type="text" 
                    value={answerInput}
                    onChange={(e) => setAnswerInput(e.target.value)}
                    placeholder="Enter exact answer (e.g. Name or ID)"
                    className="w-full bg-[#0D1117] border border-terminal-border rounded p-3 text-white focus:border-terminal-green focus:outline-none mb-4 font-mono"
                    onKeyDown={(e) => e.key === 'Enter' && checkAnswer()}
                  />

                  <div className="flex justify-end gap-3">
                      <button 
                        onClick={() => setIsSubmitModalOpen(false)}
                        className="px-4 py-2 text-sm text-terminal-text hover:text-white"
                      >
                          Cancel
                      </button>
                      <button 
                        onClick={checkAnswer}
                        disabled={gameState === 'CHECKING'}
                        className="px-6 py-2 bg-terminal-blue text-black font-bold rounded hover:bg-blue-400 disabled:opacity-50"
                      >
                          {gameState === 'CHECKING' ? 'VERIFYING...' : 'SUBMIT'}
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

export default App;

import React from 'react';
import { CASES, TABLES } from '../constants';
import { Case } from '../types';

interface SidebarProps {
    currentCase: Case;
    completedCases: string[];
    onCaseSelect: (caseId: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentCase, completedCases, onCaseSelect }) => {

    // Group cases
    const academyCases = CASES.filter(c => c.id.startsWith('academy'));
    const fieldCases = CASES.filter(c => !c.id.startsWith('academy'));

    const renderCaseList = (cases: Case[], title: string) => (
        <div className="mb-4">
            <h2 className="text-terminal-blue font-bold mb-2 uppercase text-xs tracking-widest opacity-80">{title}</h2>
            <div className="space-y-1">
                {cases.map(c => {
                    const index = CASES.findIndex(gameCase => gameCase.id === c.id);
                    const isCompleted = completedCases.includes(c.id);
                    const isActive = c.id === currentCase.id;

                    // A case is locked if it's beyond the user's progress.
                    // User can access any completed case + the immediate next unsolved one.
                    const isLocked = index > completedCases.length;

                    return (
                        <button 
                            key={c.id}
                            onClick={() => !isLocked && onCaseSelect(c.id)}
                            disabled={isLocked}
                            className={`
                                w-full text-left text-xs p-2 rounded border border-transparent transition-all flex justify-between items-center group
                                ${isActive ? 'bg-terminal-border/40 border-terminal-green/50 text-white shadow-sm shadow-green-900/10' : ''}
                                ${isCompleted && !isActive ? 'text-green-500 hover:bg-terminal-border/20' : ''}
                                ${!isCompleted && !isActive && !isLocked ? 'text-terminal-text hover:bg-terminal-border/20 hover:text-white' : ''}
                                ${isLocked ? 'opacity-30 cursor-not-allowed bg-transparent' : 'cursor-pointer'}
                            `}
                        >
                           <div className="flex flex-col truncate pr-2">
                                <span className={`font-semibold ${isActive ? 'text-white' : ''}`}>{c.title}</span>
                           </div>
                           <div className="flex-shrink-0">
                                {isCompleted ? (
                                    <span className="text-green-500">✓</span>
                                ) : isLocked ? (
                                    <span className="text-terminal-text opacity-50">🔒</span>
                                ) : (
                                    <span className={`w-2 h-2 rounded-full block ${isActive ? 'bg-terminal-green animate-pulse' : 'bg-terminal-text opacity-20 group-hover:opacity-100'}`}></span>
                                )}
                           </div>
                        </button>
                    );
                })}
            </div>
        </div>
    );

    return (
        <div className="w-64 bg-terminal-bg border-r border-terminal-border flex flex-col h-full text-sm font-mono overflow-y-auto">
            <div className="p-4 border-b border-terminal-border sticky top-0 bg-terminal-bg z-10">
                <h1 className="text-xl font-bold text-terminal-green tracking-wider">SQL-PD</h1>
                <p className="text-xs text-terminal-text opacity-50">v2.4.0-DETECTIVE</p>
            </div>

            {/* Case Progress */}
            <div className="p-4 border-b border-terminal-border bg-black/20 flex-1 overflow-y-auto max-h-[50%] scrollbar-thin">
                {renderCaseList(academyCases, "Police Academy")}
                {renderCaseList(fieldCases, "Active Investigations")}
            </div>

            {/* Schema Section */}
            <div className="p-4 flex-1 overflow-y-auto">
                <h2 className="text-terminal-blue font-bold mb-3 uppercase text-xs tracking-widest">Database Schema</h2>
                <div className="space-y-4">
                    {/* Simplified tables list for cleaner UI */}
                    <div className="text-xs text-terminal-text opacity-60 italic mb-2">Hover tables to see columns</div>
                </div>
            </div>

            {/* Real Schema List (moved to be fully scrollable if needed) */}
            <div className="px-4 pb-4 flex-1 overflow-y-auto">
                 <div className="space-y-4">
                     {TABLES.map((table: any) => (
                        <div key={table.tableName} className="group">
                            <h3 className="text-terminal-text font-bold group-hover:text-white transition-colors cursor-help flex items-center gap-2" title="Table">
                                <span className="text-terminal-blue opacity-50">▦</span> {table.tableName}
                            </h3>
                            <ul className="pl-6 mt-1 space-y-1 hidden group-hover:block transition-all">
                                {table.columns.map((col: any) => (
                                    <li key={col.name} className="text-xs text-terminal-text opacity-70 flex justify-between border-b border-white/5 pb-0.5">
                                        <span>{col.name}</span>
                                        <span className="text-terminal-blue opacity-50 text-[10px]">{col.type}</span>
                                    </li>
                                ))}
                            </ul>
