import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Case } from '../types';
import { getFastHint, getKnowledgeHelp, submitCaseReview } from '../services/geminiService';

interface ChatAssistantProps {
    currentCase: Case;
    queryHistory: string[];
    onCaseSolved: () => void;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentCase, queryHistory, onCaseSolved }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([
        { id: '1', role: 'model', text: `Detective, I'm your AI partner. I can help with SQL syntax or give you clues. Type "solve: [name]" to submit a suspect.`, timestamp: Date.now() }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [messages]);

    const handleSend = async () => {
        if (!input.trim() || isLoading) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            text: input,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsLoading(true);

        try {
            // Determine intent
            const lowerInput = input.toLowerCase();
            let aiResponseText = '';

            if (lowerInput.startsWith('solve:')) {
                // SUBMIT ANSWER -> GEMINI 3 PRO (Thinking)
                const answer = input.substring(6).trim();

                // Add a placeholder for thinking
                setMessages(prev => [...prev, {
                    id: 'thinking',
                    role: 'model',
                    text: "Analyzing case files and cross-referencing evidence...",
                    timestamp: Date.now(),
                    isThinking: true
                }]);

                const review = await submitCaseReview(
                    JSON.stringify(currentCase),
                    answer,
                    queryHistory
                );

                // Check simple exact match for game logic trigger, but let AI explain it
                const isCorrect = answer.toLowerCase() === currentCase.expectedAnswer.toLowerCase();

                setMessages(prev => prev.filter(m => m.id !== 'thinking')); // Remove thinking placeholder

                aiResponseText = review;

                if (isCorrect) {
                     // Wait a bit then trigger solved
                     setTimeout(onCaseSolved, 3000);
                }

            } else if (lowerInput.includes('how to') || lowerInput.includes('syntax') || lowerInput.includes('what is')) {
                // SQL HELP -> GEMINI 3 FLASH (Search Grounding)
                const { text, sources } = await getKnowledgeHelp(input);
                aiResponseText = text;
                if (sources.length > 0) {
                    aiResponseText += `\n\nSources:\n${sources.map(s => `- ${s}`).join('\n')}`;
                }

            } else if (lowerInput.includes('hint')) {
                // STATIC HINT + AI FLAVOR
                if (currentCase.hint) {
                    aiResponseText = `I found a note in the case file that might help:\n\n"${currentCase.hint}"`;
                } else {
                    const hint = await getFastHint(input, currentCase.briefing);
                    aiResponseText = hint;
                }
            } else {
                // HINT -> GEMINI 2.5 FLASH LITE (Fast)
                const hint = await getFastHint(input, currentCase.briefing);
                aiResponseText = hint;
            }

            const aiMsg: ChatMessage = {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: aiResponseText,
                timestamp: Date.now()
            };
            setMessages(prev => [...prev, aiMsg]);

        } catch (error) {
            setMessages(prev => [...prev, {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: "Communication error. Try again.",
                timestamp: Date.now()
            }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex flex-col h-full bg-terminal-bg border-l border-terminal-border w-96">
            <div className="p-4 border-b border-terminal-border bg-black/20">
                <h2 className="text-terminal-blue font-bold uppercase text-xs tracking-widest">AI Field Partner</h2>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div 
                            className={`
                                max-w-[90%] p-3 rounded-lg text-sm font-mono whitespace-pre-wrap
                                ${msg.role === 'user' 
                                    ? 'bg-terminal-blue/20 text-terminal-blue border border-terminal-blue/30 rounded-br-none' 
                                    : 'bg-terminal-border/40 text-terminal-text border border-terminal-border rounded-bl-none'}
                                ${msg.isThinking ? 'animate-pulse' : ''}
                            `}
                        >
                            {msg.text}
                        </div>
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>

            <div className="p-4 border-t border-terminal-border bg-black/20">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder="Ask for hint or 'solve: [name]'"
                        className="flex-1 bg-terminal-bg border border-terminal-border rounded px-3 py-2 text-sm text-terminal-text focus:outline-none focus:border-terminal-blue font-mono"
                        disabled={isLoading}
                    />
                    <button 
                        onClick={handleSend}
                        disabled={isLoading}
                        className="p-2 bg-terminal-blue/20 text-terminal-blue border border-terminal-blue/30 rounded hover:bg-terminal-blue/30 disabled:opacity-50"
                    >
                        ➤
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ChatAssistant;

import React, { useState } from 'react';

interface SqlEditorProps {
    onRun: (sql: string) => void;
    isRunning: boolean;
    answerInput: string;
    setAnswerInput: (val: string) => void;
    onSubmitAnswer: () => void;
    isChecking: boolean;
