    isRunning, 
    answerInput, 
    setAnswerInput, 
    onSubmitAnswer,
    isChecking
}) => {
    const [sql, setSql] = useState('');

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            onRun(sql);
        }
