            <textarea
                value={sql}
                onChange={(e) => setSql(e.target.value)}
                onKeyDown={handleKeyDown}
                className="flex-1 bg-[#0D1117] text-terminal-text p-4 font-mono text-base resize-none focus:outline-none focus:ring-1 focus:ring-terminal-border"
                placeholder="-- Type your SQL query here...
SELECT * FROM crime_scene_report LIMIT 5;"
                spellCheck={false}
            />
            <div className="p-3 bg-terminal-bg border-t border-terminal-border flex justify-between items-center gap-4">
                {/* Answer Section */}
