import React, { useEffect, useState } from 'react';
import Sidebar from './components/Sidebar';
import SqlEditor from './components/SqlEditor';
import ResultsTable from './components/ResultsTable';
import ChatAssistant from './components/ChatAssistant';
import { CASES } from './constants';
import { runQuery, initDB } from './services/dbService';
import { QueryResult } from './types';
import { submitCaseReview, getFastHint } from './services/geminiService';

function App() {
  const [currentCaseIndex, setCurrentCaseIndex] = useState(0);
  const [queryResult, setQueryResult] = useState<QueryResult | null>(null);
  const [queryHistory, setQueryHistory] = useState<string[]>([]);
  const [isExecuting, setIsExecuting] = useState(false);
  const [completedCases, setCompletedCases] = useState<string[]>([]);
  const [gameState, setGameState] = useState<'LOADING' | 'READY' | 'CHECKING' | 'SOLVED_ANIMATION' | 'FAILED'>('LOADING');
  const [answerInput, setAnswerInput] = useState('');
  const [feedback, setFeedback] = useState<string>('');

  // Hint State
  const [hasUsedHint, setHasUsedHint] = useState(false);
  const [activeHint, setActiveHint] = useState<string>('');

  // Persistence Load
  useEffect(() => {
    setTimeout(() => {
        initDB();
        const savedCase = localStorage.getItem('sqlpd_currentCase');
        const savedCompleted = localStorage.getItem('sqlpd_completed');

        if (savedCase) {
             const idx = parseInt(savedCase);
             if (idx < CASES.length) setCurrentCaseIndex(idx);
             else setCurrentCaseIndex(0);
        }
        if (savedCompleted) setCompletedCases(JSON.parse(savedCompleted));

        setGameState('READY');
    }, 100);
  }, []);

  // Persistence Save
  useEffect(() => {
    localStorage.setItem('sqlpd_currentCase', currentCaseIndex.toString());
    localStorage.setItem('sqlpd_completed', JSON.stringify(completedCases));
  }, [currentCaseIndex, completedCases]);

  // Reset hint state on new case
  useEffect(() => {
      setHasUsedHint(false);
      setActiveHint('');
      setAnswerInput('');
      setQueryResult(null);
      setFeedback('');
  }, [currentCaseIndex]);

  const currentCase = CASES[currentCaseIndex];

  const handleRunQuery = (sql: string) => {
    setIsExecuting(true);
    setQueryHistory(prev => [...prev, sql]);
    setFeedback(''); // Clear previous errors

    setTimeout(() => {
        const result = runQuery(sql);
        setQueryResult(result);
        setIsExecuting(false);
    }, 300);
  };

  const handleCaseSelect = (caseId: string) => {
      const index = CASES.findIndex(c => c.id === caseId);
      if (index !== -1 && index <= completedCases.length) {
          setCurrentCaseIndex(index);
          setGameState('READY');
      }
  };

  const requestHint = async () => {
      if (hasUsedHint) return;

      setHasUsedHint(true);
      setActiveHint("Decrypting clue from HQ...");

      let hintText = '';
      if (currentCase.hint) {
          hintText = currentCase.hint;
      } else {
          hintText = await getFastHint("Give me a hint", currentCase.briefing);
      }
      setActiveHint(hintText);
  };

  const checkAnswer = async () => {
      if (!answerInput.trim()) return;

      setGameState('CHECKING');

      // Exact Match Check
      const isExactMatch = answerInput.toLowerCase().trim() === currentCase.expectedAnswer.toLowerCase().trim();

      if (isExactMatch) {
          // AI Review for flavor (running in background while we show success)
          submitCaseReview(JSON.stringify(currentCase), answerInput, queryHistory)
            .then(review => setFeedback(review));

          if (!completedCases.includes(currentCase.id)) {
              setCompletedCases(prev => [...prev, currentCase.id]);
          }
          setGameState('SOLVED_ANIMATION');
      } else {
          setGameState('FAILED');
          setFeedback("Incorrect. The evidence does not match this conclusion.");
      }
  };

  const nextCase = () => {
    if (currentCaseIndex < CASES.length - 1) {
        setGameState('READY'); // Reset state first
        setCurrentCaseIndex(prev => prev + 1); // Then increment
    }
  };

  if (gameState === 'LOADING') {
    return (
        <div className="h-screen w-screen bg-black text-terminal-green flex flex-col items-center justify-center font-mono">
            <div className="animate-pulse text-2xl mb-4">ESTABLISHING SECURE CONNECTION...</div>
        </div>
    );
  }

  if (gameState === 'SOLVED_ANIMATION') {
    return (
        <div className="h-screen w-screen bg-[#0D1117] flex flex-col items-center justify-center font-mono text-center p-8 space-y-6 animate-in fade-in duration-500">
            <h1 className="text-6xl font-bold text-terminal-green mb-4">
                {currentCase.id.startsWith('academy') ? 'TRAINING COMPLETED' : 'CASE CLOSED'}
            </h1>

            <div className="bg-terminal-border/20 p-6 rounded-lg border border-terminal-green/30 max-w-2xl w-full">
                <div className="text-sm text-terminal-text opacity-50 mb-2 uppercase tracking-widest">Chief's Report</div>
                <p className="text-lg text-white whitespace-pre-wrap">
                    {feedback || "Excellent work, Detective. Your query logic was sound and the suspect has been apprehended."}
                </p>
            </div>

            <div className="flex gap-4 mt-8">
                {currentCaseIndex < CASES.length - 1 ? (
                    <button 
                        onClick={nextCase}
                        className="px-10 py-4 bg-terminal-blue text-black font-bold text-xl rounded hover:bg-blue-400 hover:scale-105 transition-all shadow-lg shadow-blue-900/20"
                    >
                        {currentCase.id.startsWith('academy') ? 'NEXT LESSON ➤' : 'NEXT CASE ➤'}
                    </button>
                ) : (
                    <div className="flex flex-col items-center gap-4">
                         <div className="text-yellow-500 text-2xl font-bold border-2 border-yellow-500/50 p-6 rounded bg-yellow-900/10">
                            ALL CASES SOLVED. <br/>
                            YOU ARE A MASTER DETECTIVE.
                        </div>
                        <button 
                            onClick={() => {
                                localStorage.clear();
                                window.location.reload();
                            }}
                            className="text-sm text-terminal-text underline hover:text-white mt-4"
                        >
                            Reset Progress
                        </button>
                    </div>
                )}
            </div>
        </div>
    );
  }

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-[#0D1117] text-[#C9D1D9]">
      <Sidebar 
        currentCase={currentCase} 
        completedCases={completedCases}
        onCaseSelect={handleCaseSelect} 
      />

      <div className="flex-1 flex flex-col min-w-0">
        {/* Header */}
        <div className="p-6 border-b border-terminal-border bg-black/40">
            <div className="flex justify-between items-start">
                <div className="flex-1 mr-4">
                    <h2 className="text-2xl font-bold text-white mb-2 flex items-center gap-2">
                        {currentCase.title}
                        {completedCases.includes(currentCase.id) && <span className="text-xs bg-green-900 text-green-300 px-2 py-0.5 rounded border border-green-700">SOLVED</span>}
                    </h2>
                    <p className="text-terminal-text opacity-80 font-mono whitespace-pre-wrap text-sm leading-relaxed">
                        {currentCase.briefing}
                    </p>
                </div>

                <div className="flex flex-col items-end gap-2 shrink-0">
                    <button 
                        onClick={requestHint}
                        disabled={hasUsedHint}
                        className={`
                            border font-bold px-4 py-2 rounded shadow-lg transition-all text-sm font-mono flex items-center gap-2
                            ${hasUsedHint 
                                ? 'bg-transparent border-terminal-border text-terminal-text opacity-50 cursor-default' 
                                : 'bg-transparent border-terminal-blue text-terminal-blue hover:bg-terminal-blue/10'}
                        `}
                    >
                        {hasUsedHint ? 'HINT RECEIVED' : 'REQUEST HINT (1 LEFT)'}
                    </button>
                    <div className="text-xs text-terminal-text opacity-50">
                        Diff: <span className="text-terminal-blue">{currentCase.difficulty}</span>
                    </div>
                </div>
            </div>

            {/* Active Hint Display */}
            {activeHint && (
                <div className="mt-4 p-3 bg-yellow-900/10 border-l-2 border-yellow-600 text-yellow-500 text-sm font-mono animate-in slide-in-from-top-2">
                    <span className="font-bold mr-2">[HINT]:</span> {activeHint}
                </div>
            )}

            {/* Error Display */}
            {gameState === 'FAILED' && (
                <div className="mt-4 p-3 bg-red-900/10 border-l-2 border-red-600 text-red-400 text-sm font-mono animate-in shake">
                    <span className="font-bold mr-2">[ERROR]:</span> {feedback}
                </div>
            )}
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col min-h-0">
            <SqlEditor 
                onRun={handleRunQuery} 
                isRunning={isExecuting}
                answerInput={answerInput}
                setAnswerInput={setAnswerInput}
                onSubmitAnswer={checkAnswer}
                isChecking={gameState === 'CHECKING'}
            />
            <ResultsTable result={queryResult} />
        </div>
      </div>

      <ChatAssistant 
        currentCase={currentCase}
        queryHistory={queryHistory}
        onCaseSolved={() => {
            // Optional: Chat can still trigger solve if user types "solve: answer" there, 
            // but primarily we use the main UI now.
            if (!completedCases.includes(currentCase.id)) {
                setCompletedCases(prev => [...prev, currentCase.id]);
            }
            setGameState('SOLVED_ANIMATION');
        }}
      />
    </div>
  );
}

export default App;

import React from 'react';
import { CASES, TABLES } from '../constants';
import { Case } from '../types';

interface SidebarProps {
    currentCase: Case;
    completedCases: string[];
    onCaseSelect: (caseId: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentCase, completedCases, onCaseSelect }) => {

    // Group cases
    const academyCases = CASES.filter(c => c.id.startsWith('academy'));
    const fieldCases = CASES.filter(c => !c.id.startsWith('academy'));

    const renderCaseList = (cases: Case[], title: string) => (
        <div className="mb-6">
            <h2 className="text-terminal-blue font-bold mb-3 uppercase text-[10px] tracking-[0.2em] opacity-80 border-b border-terminal-blue/20 pb-1">{title}</h2>
            <div className="space-y-1">
                {cases.map(c => {
                    const index = CASES.findIndex(gameCase => gameCase.id === c.id);
                    const isCompleted = completedCases.includes(c.id);
                    const isActive = c.id === currentCase.id;

                    // A case is locked if it's beyond the user's progress.
                    // User can access any completed case + the immediate next unsolved one.
                    const isLocked = index > completedCases.length;

                    return (
                        <button 
                            key={c.id}
                            onClick={() => !isLocked && onCaseSelect(c.id)}
                            disabled={isLocked}
                            className={`
                                w-full text-left text-xs p-3 rounded-md border transition-all flex justify-between items-center group relative overflow-hidden
                                ${isActive 
                                    ? 'bg-terminal-green/10 border-terminal-green text-white shadow-[0_0_10px_rgba(46,160,67,0.2)]' 
                                    : 'border-transparent'}
                                ${isCompleted && !isActive 
                                    ? 'text-terminal-text hover:bg-terminal-border/40 hover:text-white' 
                                    : ''}
                                ${!isCompleted && !isActive && !isLocked 
                                    ? 'text-white bg-terminal-border/20 hover:bg-terminal-border/50 border-terminal-border/50' 
                                    : ''}
                                ${isLocked 
                                    ? 'opacity-40 cursor-not-allowed bg-transparent text-gray-600 grayscale' 
                                    : 'cursor-pointer'}
                            `}
                        >
                           {/* Active Indicator Line */}
                           {isActive && <div className="absolute left-0 top-0 bottom-0 w-1 bg-terminal-green"></div>}

                           <div className="flex flex-col truncate pr-2 pl-2">
                                <span className={`font-semibold tracking-tight ${isActive ? 'text-white' : 'text-inherit'}`}>
                                    {c.title}
                                </span>
                                {isLocked && <span className="text-[10px] uppercase tracking-wider mt-1 opacity-50">Access Denied</span>}
                           </div>

                           <div className="flex-shrink-0 pl-2">
                                {isCompleted ? (
                                    <span className="text-terminal-green font-bold text-lg">✓</span>
                                ) : isLocked ? (
                                    <span className="text-terminal-text opacity-30 text-sm">🔒</span>
                                ) : (
                                    <span className={`w-2 h-2 rounded-full block shadow-[0_0_5px_currentColor] ${isActive ? 'bg-terminal-green animate-pulse' : 'bg-yellow-500'}`}></span>
                                )}
                           </div>
                        </button>
                    );
                })}
            </div>
        </div>
    );

    return (
        <div className="w-72 bg-[#090C10] border-r border-terminal-border flex flex-col h-full text-sm font-mono overflow-y-auto shadow-xl z-20">
            <div className="p-5 border-b border-terminal-border bg-[#090C10] sticky top-0 z-10">
                <div className="flex items-center gap-3 mb-1">
                     <div className="w-3 h-3 bg-red-500 rounded-full animate-pulse shadow-[0_0_8px_rgba(239,68,68,0.5)]"></div>
                     <h1 className="text-xl font-bold text-white tracking-widest font-sans">SQL-PD</h1>
                </div>
                <p className="text-[10px] text-terminal-text opacity-40 uppercase tracking-[0.2em] ml-6">Database Access Terminal</p>
            </div>

            {/* Case Progress */}
            <div className="p-4 flex-1 overflow-y-auto scrollbar-thin scrollbar-thumb-terminal-border scrollbar-track-transparent">
                {renderCaseList(academyCases, "Training Modules")}
                {renderCaseList(fieldCases, "Active Cases")}
            </div>

            {/* Schema Section */}
            <div className="p-4 border-t border-terminal-border bg-black/20">
                 <h2 className="text-terminal-blue font-bold mb-3 uppercase text-[10px] tracking-[0.2em] opacity-80">Schema Reference</h2>
                 <div className="space-y-1 max-h-48 overflow-y-auto pr-1 scrollbar-thin">
                     {TABLES.map((table: any) => (
                        <div key={table.tableName} className="group mb-2">
                            <h3 className="text-gray-400 text-xs font-bold group-hover:text-white transition-colors cursor-help flex items-center gap-2 select-none">
                                <span className="text-terminal-blue opacity-50 text-[10px]">▦</span> {table.tableName}
                            </h3>
                            <ul className="pl-5 mt-1 space-y-0.5 hidden group-hover:block transition-all border-l border-terminal-border/30 ml-1.5">
                                {table.columns.map((col: any) => (
                                    <li key={col.name} className="text-[10px] text-gray-500 flex justify-between hover:text-gray-300">
                                        <span>{col.name}</span>
                                        <span className="text-terminal-blue/40">{col.type}</span>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

