import React from 'react';
import { CASES, TABLES } from '../constants';
import { Case } from '../types';
import { 
    IconFolder, 
    IconCheck, 
    IconLock, 
    IconDatabase, 
    IconChevronLeft, 
    IconChevronRight,
    IconSettings,
    IconUser
} from './Icons';

interface SidebarProps {
    currentCase: Case;
    completedCases: string[];
    onCaseSelect: (caseId: string) => void;
    badgeId: string;
    isCollapsed: boolean;
    toggleSidebar: () => void;
    onOpenSettings: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    currentCase, 
    completedCases, 
    onCaseSelect, 
    badgeId, 
    isCollapsed,
    toggleSidebar,
    onOpenSettings
}) => {

    const academyCases = CASES.filter(c => c.id.startsWith('academy'));
    const fieldCases = CASES.filter(c => !c.id.startsWith('academy'));

    // Helper to render a case list item
    const CaseItem = ({ c }: { c: Case }) => {
        const index = CASES.findIndex(gameCase => gameCase.id === c.id);
        const isCompleted = completedCases.includes(c.id);
        const isActive = c.id === currentCase.id;
        const isLocked = index > completedCases.length;

        return (
            <button 
                onClick={() => !isLocked && onCaseSelect(c.id)}
                disabled={isLocked}
                title={isCollapsed ? c.title : undefined}
                className={`
                    group w-full flex items-center gap-3 p-2 rounded-lg text-sm transition-all duration-200 relative overflow-hidden
                    ${isActive 
                        ? 'bg-terminal-blue/10 text-white shadow-[inset_0_0_0_1px_rgba(88,166,255,0.4)]' 
                        : 'text-gray-400 hover:bg-white/5 hover:text-gray-200'}
                    ${isLocked ? 'opacity-40 cursor-not-allowed grayscale' : 'cursor-pointer'}
                `}
            >
                {isActive && (
                    <div className="absolute left-0 top-0 bottom-0 w-[2px] bg-terminal-blue shadow-[0_0_8px_#58A6FF]"></div>
                )}

                <div className={`
                    flex-shrink-0 w-6 h-6 flex items-center justify-center rounded 
                    ${isCompleted && !isActive ? 'text-terminal-green' : ''}
                    ${isActive ? 'text-terminal-blue' : ''}
                    ${!isCompleted && !isActive && !isLocked ? 'text-yellow-500' : ''}
                `}>
                    {isCompleted ? <IconCheck className="w-4 h-4" /> : 
                     isLocked ? <IconLock className="w-3 h-3" /> : 
                     <IconFolder className="w-4 h-4" />}
                </div>

                {!isCollapsed && (
                    <div className="flex-1 text-left truncate">
                        <div className="font-medium truncate">{c.title}</div>
                    </div>
                )}
            </button>
        );
    };

    return (
        <div 
            className={`
                relative h-full bg-[#0D1117]/95 backdrop-blur-md border-r border-terminal-border flex flex-col transition-all duration-300 ease-in-out z-20 shadow-2xl
                ${isCollapsed ? 'w-16' : 'w-72'}
            `}
        >
            {/* Header / Logo */}
            <div className={`h-16 flex items-center border-b border-terminal-border ${isCollapsed ? 'justify-center' : 'justify-between px-4'}`}>
                {!isCollapsed && (
                    <div className="flex items-center gap-2">
                        <div className="w-2 h-2 bg-terminal-blue rounded-full animate-pulse shadow-[0_0_8px_rgba(88,166,255,0.8)]"></div>
                        <h1 className="text-lg font-bold text-white tracking-widest font-sans">SQL-PD</h1>
                    </div>
                )}

                <button 
                    onClick={toggleSidebar}
                    className="p-1.5 rounded-md text-gray-400 hover:bg-white/10 hover:text-white transition-colors"
                >
                    {isCollapsed ? <IconChevronRight className="w-5 h-5" /> : <IconChevronLeft className="w-4 h-4" />}
                </button>
            </div>

            {/* Content Area */}
            <div className="flex-1 overflow-y-auto overflow-x-hidden scrollbar-thin scrollbar-thumb-gray-800 scrollbar-track-transparent">

                {/* Cases Section */}
                <div className="p-3 space-y-6">
                    <div>
                        {!isCollapsed && (
                            <h2 className="px-2 text-[10px] uppercase font-bold text-gray-500 tracking-widest mb-2 flex items-center gap-2">
                                <span className="w-1 h-1 bg-gray-500 rounded-full"></span>
                                Training
                            </h2>
                        )}
                        <div className="space-y-1">
                            {academyCases.map(c => <CaseItem key={c.id} c={c} />)}
                        </div>
                    </div>

                    <div>
                        {!isCollapsed && (
                            <h2 className="px-2 text-[10px] uppercase font-bold text-gray-500 tracking-widest mb-2 flex items-center gap-2">
                                <span className="w-1 h-1 bg-gray-500 rounded-full"></span>
                                Active Files
                            </h2>
                        )}
                        <div className="space-y-1">
                            {fieldCases.map(c => <CaseItem key={c.id} c={c} />)}
                        </div>
                    </div>
                </div>

                {/* Schema Section (Only show if not collapsed, or show icon tooltips) */}
                {!isCollapsed && (
                    <div className="p-4 border-t border-terminal-border/50">
                        <h2 className="text-[10px] uppercase font-bold text-gray-500 tracking-widest mb-3 flex items-center gap-2">
                            <IconDatabase className="w-3 h-3" /> Schema
                        </h2>
                        <div className="space-y-1 opacity-80">
                            {TABLES.map(table => (
                                <div key={table.tableName} className="group relative">
                                    <div className="text-xs text-gray-400 font-mono hover:text-white cursor-help py-1">
                                        {table.tableName}
                                    </div>
                                    {/* Hover Tooltip for Schema */}
                                    <div className="absolute left-0 bottom-full mb-2 w-48 bg-black border border-terminal-border p-2 rounded shadow-xl hidden group-hover:block z-50">
                                        <div className="text-[10px] text-terminal-blue font-bold mb-1 border-b border-gray-800 pb-1">COLUMNS</div>
                                        {table.columns.map(col => (
                                            <div key={col.name} className="flex justify-between text-[10px] text-gray-400">
                                                <span>{col.name}</span>
                                                <span className="opacity-50">{col.type}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* Footer / Profile */}
            <div className="p-3 border-t border-terminal-border bg-black/20">
                <button 
                    onClick={onOpenSettings}
                    className={`
                        w-full flex items-center rounded-lg p-2 transition-all hover:bg-white/5 border border-transparent hover:border-terminal-border
                        ${isCollapsed ? 'justify-center' : 'justify-between'}
                    `}
                >
                    <div className="flex items-center gap-3">
                        <div className="w-8 h-8 rounded bg-gradient-to-tr from-gray-800 to-gray-700 flex items-center justify-center border border-gray-600 shadow-lg">
                            <IconUser className="w-4 h-4 text-gray-300" />
                        </div>
                        {!isCollapsed && (
                            <div className="text-left">
                                <div className="text-xs font-bold text-white">Detective</div>
                                <div className="text-[10px] text-terminal-green font-mono">#{badgeId}</div>
                            </div>
                        )}
                    </div>
                    {!isCollapsed && <IconSettings className="w-4 h-4 text-gray-500" />}
                </button>
            </div>
        </div>
    );
};

export default Sidebar;

import React, { useEffect, useState } from 'react';
import Sidebar from './components/Sidebar';
import SqlEditor from './components/SqlEditor';
import ResultsTable from './components/ResultsTable';
import ChatAssistant from './components/ChatAssistant';
import SettingsModal from './components/SettingsModal';
import { CASES } from './constants';
import { runQuery, initDB } from './services/dbService';
import { QueryResult } from './types';
import { submitCaseReview, getFastHint } from './services/geminiService';

function App() {
  const [currentCaseIndex, setCurrentCaseIndex] = useState(0);
  const [queryResult, setQueryResult] = useState<QueryResult | null>(null);
  const [queryHistory, setQueryHistory] = useState<string[]>([]);
  const [isExecuting, setIsExecuting] = useState(false);
  const [completedCases, setCompletedCases] = useState<string[]>([]);
  const [gameState, setGameState] = useState<'LOADING' | 'READY' | 'CHECKING' | 'SOLVED_ANIMATION' | 'FAILED'>('LOADING');
  const [answerInput, setAnswerInput] = useState('');
  const [feedback, setFeedback] = useState<string>('');
  const [badgeId, setBadgeId] = useState<string>('Unknown');

  // UI States
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Hint State
  const [hasUsedHint, setHasUsedHint] = useState(false);
  const [activeHint, setActiveHint] = useState<string>('');

  // Persistence Load
  useEffect(() => {
    setTimeout(() => {
        initDB();
        const savedCase = localStorage.getItem('sqlpd_currentCase');
        const savedCompleted = localStorage.getItem('sqlpd_completed');
        const savedBadge = localStorage.getItem('sqlpd_badgeId');

        // Restore progress
        if (savedCase) {
             const idx = parseInt(savedCase);
             if (idx < CASES.length) setCurrentCaseIndex(idx);
             else setCurrentCaseIndex(0);
        }
        if (savedCompleted) setCompletedCases(JSON.parse(savedCompleted));

        // Restore or Create Badge ID (Simulated Login)
        if (savedBadge) {
            setBadgeId(savedBadge);
        } else {
            const newBadge = Math.floor(10000 + Math.random() * 90000).toString();
            localStorage.setItem('sqlpd_badgeId', newBadge);
            setBadgeId(newBadge);
        }

        setGameState('READY');
    }, 100);
  }, []);

  // Persistence Save
  useEffect(() => {
    localStorage.setItem('sqlpd_currentCase', currentCaseIndex.toString());
    localStorage.setItem('sqlpd_completed', JSON.stringify(completedCases));
  }, [currentCaseIndex, completedCases]);

  // Reset hint state on new case
  useEffect(() => {
      setHasUsedHint(false);
      setActiveHint('');
      setAnswerInput('');
      setQueryResult(null);
      setFeedback('');
  }, [currentCaseIndex]);

  const currentCase = CASES[currentCaseIndex];

  const handleRunQuery = (sql: string) => {
    setIsExecuting(true);
    setQueryHistory(prev => [...prev, sql]);
    setFeedback(''); // Clear previous errors

    setTimeout(() => {
        const result = runQuery(sql);
        setQueryResult(result);
        setIsExecuting(false);
    }, 300);
  };

  const handleCaseSelect = (caseId: string) => {
      const index = CASES.findIndex(c => c.id === caseId);
      if (index !== -1 && index <= completedCases.length) {
          setCurrentCaseIndex(index);
          setGameState('READY');
      }
  };

  const handleResetProgress = () => {
      if (window.confirm("WARNING: This will wipe your badge history and reset all progress. Are you sure?")) {
          localStorage.clear();
          window.location.reload();
      }
  };

  const requestHint = async () => {
      if (hasUsedHint) return;

      setHasUsedHint(true);
      setActiveHint("Decrypting clue from HQ...");

      let hintText = '';
      if (currentCase.hint) {
          hintText = currentCase.hint;
      } else {
          hintText = await getFastHint("Give me a hint", currentCase.briefing);
      }
      setActiveHint(hintText);
  };

  const checkAnswer = async () => {
      if (!answerInput.trim()) return;

      setGameState('CHECKING');

      const normalize = (str: string) => str.toLowerCase().replace(/\s+/g, ' ').trim().replace(/;$/, '');

      const input = normalize(answerInput);
      const expected = normalize(currentCase.expectedAnswer);
      const solution = currentCase.solutionQuery ? normalize(currentCase.solutionQuery) : '';

      const isMatch = input === expected || (solution && input === solution);

      if (isMatch) {
          submitCaseReview(JSON.stringify(currentCase), answerInput, queryHistory)
            .then(review => setFeedback(review));

          setGameState('SOLVED_ANIMATION');
      } else {
          setGameState('FAILED');

          let failMessage = "Incorrect. The evidence does not match this conclusion.";

          if (queryResult) {
              if (queryResult.error) {
                   failMessage = "Your investigation is halted by a Syntax Error. Check the red error message in the table below.";
              } else if (queryResult.data.length === 0) {
                   failMessage = "Your query returned ZERO rows. You might be filtering too strictly or there is no matching data.";
              } else {
                   const rawData = JSON.stringify(queryResult.data).toLowerCase();
                   if (rawData.includes(expected)) {
                        failMessage = "Target Identified! The correct answer IS listed in your query results. Read the table carefully and submit the exact value.";
                   } else {
                        failMessage = "Query executed successfully, but the answer is NOT in the results. You are asking the wrong questions.";
                   }
              }
          } else {
              failMessage = "You haven't run any queries yet. Don't guess—investigate! Use the Query Console.";
          }

          setFeedback(failMessage);
      }
  };

  const advanceToNextLevel = () => {
    if (!completedCases.includes(currentCase.id)) {
        setCompletedCases(prev => [...prev, currentCase.id]);
    }
    if (currentCaseIndex < CASES.length - 1) {
        setGameState('READY');
        setCurrentCaseIndex(prev => prev + 1);
    } else {
        setGameState('SOLVED_ANIMATION'); 
    }
  };

  if (gameState === 'LOADING') {
    return (
        <div className="h-screen w-screen bg-[#000] flex flex-col items-center justify-center font-mono relative overflow-hidden">
            <div className="absolute inset-0 bg-[linear-gradient(to_right,#111_1px,transparent_1px),linear-gradient(to_bottom,#111_1px,transparent_1px)] bg-[size:24px_24px] opacity-20"></div>
            <div className="animate-pulse text-2xl mb-4 text-terminal-green z-10 font-bold tracking-[0.2em]">INITIALIZING SYSTEM...</div>
        </div>
    );
  }

  // Solved View
  if (gameState === 'SOLVED_ANIMATION') {
    const isLastCase = currentCaseIndex === CASES.length - 1;
    const isGameFullyComplete = isLastCase && completedCases.includes(currentCase.id);

    return (
        <div className="h-screen w-screen bg-[#0D1117] flex flex-col items-center justify-center font-mono text-center p-8 space-y-6 animate-in fade-in duration-500 relative overflow-hidden">
             {/* Background Grid */}
            <div className="absolute inset-0 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:24px_24px]"></div>

            <div className="z-10 w-full max-w-3xl">
                {isGameFullyComplete ? (
                     <div className="space-y-6">
                        <div className="inline-block p-4 rounded-full bg-yellow-500/10 border border-yellow-500/50 mb-4 animate-bounce">
                             <span className="text-4xl">🏆</span>
                        </div>
                        <h1 className="text-6xl font-bold text-yellow-500 mb-4 tracking-tighter">
                            MISSION ACCOMPLISHED
                        </h1>
                        <div className="text-white text-xl border border-yellow-500/20 p-8 rounded-xl bg-gradient-to-br from-yellow-900/10 to-transparent backdrop-blur-sm">
                            <p className="font-bold mb-2">ALL INVESTIGATIONS CLOSED.</p>
                            <span className="text-sm opacity-70 block">Your record has been permanently added to the hall of fame.</span>
                        </div>
                        <button 
                            onClick={handleResetProgress}
                            className="px-8 py-3 mt-8 text-terminal-text hover:text-white border border-terminal-border rounded-lg hover:bg-white/5 transition-all"
                        >
                            Reset Career (Clear Data)
                        </button>
                     </div>
                ) : (
                    <>
                        <h1 className="text-5xl font-bold text-transparent bg-clip-text bg-gradient-to-b from-terminal-green to-emerald-800 mb-6 tracking-tight">
                            {currentCase.id.startsWith('academy') ? 'MODULE COMPLETE' : 'CASE CLOSED'}
                        </h1>

                        <div className="bg-[#0D1117]/80 backdrop-blur-xl p-8 rounded-2xl border border-terminal-green/20 shadow-[0_0_30px_rgba(46,160,67,0.1)] w-full">
                            <div className="text-xs text-terminal-text opacity-50 mb-4 uppercase tracking-[0.2em] font-bold">Chief's Report</div>
                            <p className="text-lg text-white whitespace-pre-wrap leading-relaxed">
                                {feedback || "Excellent work, Detective. Your query logic was sound and the suspect has been apprehended."}
                            </p>
                        </div>

                        <div className="flex justify-center gap-4 mt-10">
                            <button 
                                onClick={advanceToNextLevel}
                                className="group relative px-8 py-4 bg-white text-black font-bold text-lg rounded-full hover:scale-105 transition-all shadow-[0_0_20px_rgba(255,255,255,0.3)] overflow-hidden"
                            >
                                <span className="relative z-10 flex items-center gap-2">
                                    {isLastCase ? 'CLOSE FILE' : 'NEXT ASSIGNMENT'} 
                                    <span className="group-hover:translate-x-1 transition-transform">→</span>
                                </span>
                            </button>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
  }

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-[#0D1117] text-[#C9D1D9] font-sans">
      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        badgeId={badgeId}
        completedCount={completedCases.length}
        totalCases={CASES.length}
        onReset={handleResetProgress}
      />

      <Sidebar 
        currentCase={currentCase} 
        completedCases={completedCases}
        onCaseSelect={handleCaseSelect} 
        badgeId={badgeId}
        isCollapsed={isSidebarCollapsed}
        toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        onOpenSettings={() => setIsSettingsOpen(true)}
      />

      <div className="flex-1 flex flex-col min-w-0 relative">
        {/* Subtle Background Grid for the Workspace */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,#80808008_1px,transparent_1px),linear-gradient(to_bottom,#80808008_1px,transparent_1px)] bg-[size:32px_32px] pointer-events-none"></div>

        {/* Header */}
        <div className="p-6 border-b border-terminal-border bg-[#0D1117]/50 backdrop-blur-sm z-10">
            <div className="flex justify-between items-start">
                <div className="flex-1 mr-4">
                    <div className="flex items-center gap-3 mb-2">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${
                            currentCase.difficulty === 'Easy' ? 'border-green-800 bg-green-900/20 text-green-400' :
                            currentCase.difficulty === 'Medium' ? 'border-yellow-800 bg-yellow-900/20 text-yellow-400' :
                            'border-red-800 bg-red-900/20 text-red-400'
                        }`}>
                            {currentCase.difficulty}
                        </span>
                        {completedCases.includes(currentCase.id) && (
                            <span className="text-[10px] font-bold bg-terminal-green text-black px-2 py-0.5 rounded">SOLVED</span>
                        )}
                    </div>
                    <h2 className="text-3xl font-bold text-white mb-2 tracking-tight">
                        {currentCase.title}
                    </h2>
                    <p className="text-gray-400 text-sm leading-relaxed max-w-3xl">
                        {currentCase.briefing}
                    </p>
                </div>

                <div className="flex flex-col items-end gap-2 shrink-0">
                    <button 
                        onClick={requestHint}
                        disabled={hasUsedHint || completedCases.includes(currentCase.id)}
                        className={`
                            group relative px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all
                            ${hasUsedHint || completedCases.includes(currentCase.id)
                                ? 'bg-transparent text-gray-600 border border-gray-800 cursor-default' 
                                : 'bg-terminal-blue/10 text-terminal-blue border border-terminal-blue/30 hover:bg-terminal-blue/20'}
                        `}
                    >
                        {hasUsedHint ? 'HINT RECEIVED' : 'REQUEST HINT'}
                    </button>
                </div>
            </div>

            {activeHint && (
                <div className="mt-4 p-4 rounded-lg bg-yellow-500/5 border border-yellow-500/20 text-yellow-500 text-sm animate-in slide-in-from-top-2 flex gap-3">
                    <span className="font-bold">💡 HINT:</span> 
                    {activeHint}
                </div>
            )}

            {gameState === 'FAILED' && (
                <div className="mt-4 p-4 rounded-lg bg-red-500/5 border border-red-500/20 text-red-400 text-sm animate-in shake flex gap-3">
                    <span className="font-bold">⛔ ERROR:</span> 
                    {feedback}
                </div>
            )}
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col min-h-0 z-0">
            <SqlEditor 
                onRun={handleRunQuery} 
                isRunning={isExecuting}
                answerInput={answerInput}
                setAnswerInput={setAnswerInput}
                onSubmitAnswer={checkAnswer}
                isChecking={gameState === 'CHECKING'}
            />
            <ResultsTable result={queryResult} />
        </div>
      </div>

      {/* Chat is fixed width on the right, could be collapsible too in future iterations */}
      <ChatAssistant 
        currentCase={currentCase}
        queryHistory={queryHistory}
        onCaseSolved={() => {
            if (!completedCases.includes(currentCase.id)) {
                 setGameState('SOLVED_ANIMATION');
            }
        }}
      />
    </div>
  );
}

