import React, { useEffect, useState } from 'react';
import Sidebar from './components/Sidebar';
import SqlEditor from './components/SqlEditor';
import ResultsTable from './components/ResultsTable';
import ChatAssistant from './components/ChatAssistant';
import SettingsModal from './components/SettingsModal';
import { CASES } from './constants';
import { runQuery, initDB } from './services/dbService';
import { QueryResult } from './types';
import { submitCaseReview, getFastHint } from './services/geminiService';

function App() {
  // Game State
  const [gameState, setGameState] = useState<'LOADING' | 'READY' | 'CHECKING' | 'SOLVED_ANIMATION' | 'FAILED'>('LOADING');

  // Persistence Data
  const [currentCaseIndex, setCurrentCaseIndex] = useState(0);
  const [completedCases, setCompletedCases] = useState<string[]>([]);
  const [badgeId, setBadgeId] = useState<string>('Unknown');
  const [officerName, setOfficerName] = useState<string>('Detective');
  const [queryHistory, setQueryHistory] = useState<string[]>([]);
  const [sqlCode, setSqlCode] = useState<string>(''); // Lifted state for persistence

  // Theme State
  const [theme, setTheme] = useState<'dark' | 'light'>(() => {
      return (localStorage.getItem('sqlpd_theme') as 'dark' | 'light') || 'dark';
  });

  // Execution State
  const [queryResult, setQueryResult] = useState<QueryResult | null>(null);
  const [isExecuting, setIsExecuting] = useState(false);
  const [answerInput, setAnswerInput] = useState('');
  const [feedback, setFeedback] = useState<string>('');

  // UI States
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // Hint State
  const [hasUsedHint, setHasUsedHint] = useState(false);
  const [activeHint, setActiveHint] = useState<string>('');

  // 0. THEME EFFECT
  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
        root.classList.add('dark');
    } else {
        root.classList.remove('dark');
    }
    localStorage.setItem('sqlpd_theme', theme);
  }, [theme]);

  const toggleTheme = () => {
      setTheme(prev => prev === 'dark' ? 'light' : 'dark');
  };

  // 1. INITIALIZATION & RESTORE
  useEffect(() => {
    // Poll for Alasql to be ready (Script loading)
    const dbInitInterval = setInterval(() => {
        if (window.alasql) {
            clearInterval(dbInitInterval);
            initDB();

            // Restore Persistent Data
            const savedCase = localStorage.getItem('sqlpd_currentCase');
            const savedCompleted = localStorage.getItem('sqlpd_completed');
            const savedBadge = localStorage.getItem('sqlpd_badgeId');
            const savedName = localStorage.getItem('sqlpd_officerName');
            const savedHistory = localStorage.getItem('sqlpd_queryHistory');
            const savedSql = localStorage.getItem('sqlpd_editorContent');

            if (savedCase) {
                 const idx = parseInt(savedCase);
                 if (idx < CASES.length) setCurrentCaseIndex(idx);
            }
            if (savedCompleted) setCompletedCases(JSON.parse(savedCompleted));
            if (savedName) setOfficerName(savedName);
            if (savedHistory) setQueryHistory(JSON.parse(savedHistory));
            if (savedSql) setSqlCode(savedSql);

            // Restore or Create Badge ID
            if (savedBadge) {
                setBadgeId(savedBadge);
            } else {
                const newBadge = Math.floor(10000 + Math.random() * 90000).toString();
                localStorage.setItem('sqlpd_badgeId', newBadge);
                setBadgeId(newBadge);
            }

            setGameState('READY');
        }
    }, 100);

    return () => clearInterval(dbInitInterval);
  }, []);

  // 2. PERSISTENCE SAVER
  useEffect(() => {
    if (gameState === 'LOADING') return; // Don't save empty state during boot

    localStorage.setItem('sqlpd_currentCase', currentCaseIndex.toString());
    localStorage.setItem('sqlpd_completed', JSON.stringify(completedCases));
    localStorage.setItem('sqlpd_officerName', officerName);
    localStorage.setItem('sqlpd_queryHistory', JSON.stringify(queryHistory));
    localStorage.setItem('sqlpd_editorContent', sqlCode);
  }, [currentCaseIndex, completedCases, officerName, queryHistory, sqlCode, gameState]);

  // Reset hint/feedback on new case
  useEffect(() => {
      setHasUsedHint(false);
      setActiveHint('');
      setAnswerInput('');
      setQueryResult(null);
      setFeedback('');
      // We do NOT reset sqlCode here, giving users a scratchpad feeling across cases if they want
  }, [currentCaseIndex]);

  const currentCase = CASES[currentCaseIndex];

  const handleRunQuery = (sql: string) => {
    setIsExecuting(true);
    setQueryHistory(prev => [...prev, sql]);
    setFeedback(''); // Clear previous errors

    // Simulate network delay for realism
    setTimeout(() => {
        const result = runQuery(sql);
        setQueryResult(result);
        setIsExecuting(false);
    }, 300);
  };

  const handleCaseSelect = (caseId: string) => {
      const index = CASES.findIndex(c => c.id === caseId);
      if (index !== -1 && index <= completedCases.length) {
          setCurrentCaseIndex(index);
          setGameState('READY');
      }
  };

  const handleResetProgress = () => {
      if (window.confirm("WARNING: This will wipe your badge history, profile, and reset all progress. Are you sure?")) {
          localStorage.clear();
          window.location.reload();
      }
  };

  const requestHint = async () => {
      if (hasUsedHint) return;

      setHasUsedHint(true);
      setActiveHint("Decrypting clue from HQ...");

      let hintText = '';
      if (currentCase.hint) {
          hintText = currentCase.hint;
      } else {
          hintText = await getFastHint("Give me a hint", currentCase.briefing);
      }
      setActiveHint(hintText);
  };

  const checkAnswer = async () => {
      if (!answerInput.trim()) return;

      setGameState('CHECKING');

      const normalize = (str: string) => str.toLowerCase().replace(/\s+/g, ' ').trim().replace(/;$/, '');

      const input = normalize(answerInput);
      const expected = normalize(currentCase.expectedAnswer);
      const solution = currentCase.solutionQuery ? normalize(currentCase.solutionQuery) : '';

      const isMatch = input === expected || (solution && input === solution);

      if (isMatch) {
          submitCaseReview(JSON.stringify(currentCase), answerInput, queryHistory)
            .then(review => setFeedback(review));

          setGameState('SOLVED_ANIMATION');
      } else {
          setGameState('FAILED');

          let failMessage = "Incorrect. The evidence does not match this conclusion.";

          if (queryResult) {
              if (queryResult.error) {
                   failMessage = "Your investigation is halted by a Syntax Error. Check the red error message in the table below.";
              } else if (queryResult.data.length === 0) {
                   failMessage = "Your query returned ZERO rows. You might be filtering too strictly or there is no matching data.";
              } else {
                   const rawData = JSON.stringify(queryResult.data).toLowerCase();
                   if (rawData.includes(expected)) {
                        failMessage = "Target Identified! The correct answer IS listed in your query results. Read the table carefully and submit the exact value.";
                   } else {
                        failMessage = "Query executed successfully, but the answer is NOT in the results. You are asking the wrong questions.";
                   }
              }
          } else {
              failMessage = "You haven't run any queries yet. Don't guess—investigate! Use the Query Console.";
          }

          setFeedback(failMessage);
      }
  };

  const advanceToNextLevel = () => {
    if (!completedCases.includes(currentCase.id)) {
        setCompletedCases(prev => [...prev, currentCase.id]);
    }
    if (currentCaseIndex < CASES.length - 1) {
        setGameState('READY');
        setCurrentCaseIndex(prev => prev + 1);
    } else {
        setGameState('SOLVED_ANIMATION'); 
    }
  };

  if (gameState === 'LOADING') {
    return (
        <div className="h-screen w-screen bg-terminal-bg flex flex-col items-center justify-center font-mono relative overflow-hidden">
            <div className="absolute inset-0 bg-[linear-gradient(to_right,var(--color-terminal-border)_1px,transparent_1px),linear-gradient(to_bottom,var(--color-terminal-border)_1px,transparent_1px)] bg-[size:24px_24px] opacity-10"></div>
            <div className="flex flex-col items-center z-10">
                <div className="w-16 h-16 border-4 border-terminal-blue border-t-transparent rounded-full animate-spin mb-4"></div>
                <div className="animate-pulse text-lg text-terminal-green font-bold tracking-[0.2em]">CONNECTING TO MAINFRAME...</div>
            </div>
        </div>
    );
  }

  // Solved View
  if (gameState === 'SOLVED_ANIMATION') {
    const isLastCase = currentCaseIndex === CASES.length - 1;
    const isGameFullyComplete = isLastCase && completedCases.includes(currentCase.id);

    return (
        <div className="h-screen w-screen bg-terminal-bg flex flex-col items-center justify-center font-mono text-center p-8 space-y-6 animate-in fade-in duration-500 relative overflow-hidden text-terminal-text">
             {/* Background Grid */}
            <div className="absolute inset-0 bg-[linear-gradient(to_right,var(--color-terminal-border)_1px,transparent_1px),linear-gradient(to_bottom,var(--color-terminal-border)_1px,transparent_1px)] bg-[size:24px_24px] opacity-10"></div>

            <div className="z-10 w-full max-w-3xl">
                {isGameFullyComplete ? (
                     <div className="space-y-6">
                        <div className="inline-block p-4 rounded-full bg-yellow-500/10 border border-yellow-500/50 mb-4 animate-bounce">
                             <span className="text-4xl">🏆</span>
                        </div>
                        <h1 className="text-6xl font-bold text-yellow-500 mb-4 tracking-tighter">
                            MISSION ACCOMPLISHED
                        </h1>
                        <div className="text-terminal-text text-xl border border-yellow-500/20 p-8 rounded-xl bg-gradient-to-br from-yellow-900/10 to-transparent backdrop-blur-sm">
                            <p className="font-bold mb-2">ALL INVESTIGATIONS CLOSED.</p>
                            <span className="text-sm opacity-70 block">Congratulations, {officerName}. Your record has been permanently added to the hall of fame.</span>
                        </div>
                        <button 
                            onClick={handleResetProgress}
                            className="px-8 py-3 mt-8 text-terminal-text hover:text-terminal-text border border-terminal-border rounded-lg hover:bg-terminal-surface transition-all"
                        >
                            Reset Career (Clear Data)
                        </button>
                     </div>
                ) : (
                    <>
                        <h1 className="text-5xl font-bold text-transparent bg-clip-text bg-gradient-to-b from-terminal-green to-emerald-800 mb-6 tracking-tight">
                            {currentCase.id.startsWith('academy') ? 'MODULE COMPLETE' : 'CASE CLOSED'}
                        </h1>

                        <div className="bg-terminal-surface/90 backdrop-blur-xl p-8 rounded-2xl border border-terminal-green/20 shadow-[0_0_30px_rgba(46,160,67,0.1)] w-full">
                            <div className="text-xs text-terminal-text opacity-50 mb-4 uppercase tracking-[0.2em] font-bold">Chief's Report</div>
                            <p className="text-lg text-terminal-text whitespace-pre-wrap leading-relaxed">
                                {feedback || `Excellent work, ${officerName}. Your query logic was sound and the suspect has been apprehended.`}
                            </p>
                        </div>

                        <div className="flex justify-center gap-4 mt-10">
                            <button 
                                onClick={advanceToNextLevel}
                                className="group relative px-8 py-4 bg-terminal-text text-terminal-bg font-bold text-lg rounded-full hover:scale-105 transition-all shadow-[0_0_20px_rgba(100,100,100,0.3)] overflow-hidden"
                            >
                                <span className="relative z-10 flex items-center gap-2">
                                    {isLastCase ? 'CLOSE FILE' : 'NEXT ASSIGNMENT'} 
                                    <span className="group-hover:translate-x-1 transition-transform">→</span>
                                </span>
                            </button>
                        </div>
                    </>
                )}
            </div>
        </div>
    );
  }

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-terminal-bg text-terminal-text font-sans transition-colors duration-300">
      <SettingsModal 
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        badgeId={badgeId}
        completedCount={completedCases.length}
        totalCases={CASES.length}
        onReset={handleResetProgress}
        officerName={officerName}
        setOfficerName={setOfficerName}
      />

      <Sidebar 
        currentCase={currentCase} 
        completedCases={completedCases}
        onCaseSelect={handleCaseSelect} 
        badgeId={badgeId}
        officerName={officerName}
        isCollapsed={isSidebarCollapsed}
        toggleSidebar={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
        onOpenSettings={() => setIsSettingsOpen(true)}
        theme={theme}
        toggleTheme={toggleTheme}
      />

      <div className="flex-1 flex flex-col min-w-0 relative">
        {/* Subtle Background Grid for the Workspace */}
        <div className="absolute inset-0 bg-[linear-gradient(to_right,var(--color-terminal-border)_1px,transparent_1px),linear-gradient(to_bottom,var(--color-terminal-border)_1px,transparent_1px)] bg-[size:32px_32px] opacity-[0.03] pointer-events-none"></div>

        {/* Header */}
        <div className="p-6 border-b border-terminal-border bg-terminal-bg/50 backdrop-blur-sm z-10 transition-colors">
            <div className="flex justify-between items-start">
                <div className="flex-1 mr-4">
                    <div className="flex items-center gap-3 mb-2">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border ${
                            currentCase.difficulty === 'Easy' ? 'border-green-800 bg-green-900/20 text-green-500' :
                            currentCase.difficulty === 'Medium' ? 'border-yellow-800 bg-yellow-900/20 text-yellow-500' :
                            'border-red-800 bg-red-900/20 text-red-500'
                        }`}>
                            {currentCase.difficulty}
                        </span>
                        {completedCases.includes(currentCase.id) && (
                            <span className="text-[10px] font-bold bg-terminal-green text-black px-2 py-0.5 rounded">SOLVED</span>
                        )}
                    </div>
                    <h2 className="text-3xl font-bold text-terminal-text mb-2 tracking-tight">
                        {currentCase.title}
                    </h2>
                    <p className="text-terminal-text/70 text-sm leading-relaxed max-w-3xl">
                        {currentCase.briefing}
                    </p>
                </div>

                <div className="flex flex-col items-end gap-2 shrink-0">
                    <button 
                        onClick={requestHint}
                        disabled={hasUsedHint || completedCases.includes(currentCase.id)}
                        className={`
                            group relative px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all
                            ${hasUsedHint || completedCases.includes(currentCase.id)
                                ? 'bg-transparent text-gray-500 border border-terminal-border cursor-default' 
                                : 'bg-terminal-blue/10 text-terminal-blue border border-terminal-blue/30 hover:bg-terminal-blue/20'}
                        `}
                    >
                        {hasUsedHint ? 'HINT RECEIVED' : 'REQUEST HINT'}
                    </button>
                </div>
            </div>

            {activeHint && (
                <div className="mt-4 p-4 rounded-lg bg-yellow-500/5 border border-yellow-500/20 text-yellow-500 text-sm animate-in slide-in-from-top-2 flex gap-3">
                    <span className="font-bold">💡 HINT:</span> 
                    {activeHint}
                </div>
            )}

            {gameState === 'FAILED' && (
                <div className="mt-4 p-4 rounded-lg bg-red-500/5 border border-red-500/20 text-red-500 text-sm animate-in shake flex gap-3">
                    <span className="font-bold">⛔ ERROR:</span> 
                    {feedback}
                </div>
            )}
        </div>

        {/* Main Workspace */}
        <div className="flex-1 flex flex-col min-h-0 z-0">
            <SqlEditor 
                sql={sqlCode}
                onChange={setSqlCode}
                onRun={handleRunQuery} 
                isRunning={isExecuting}
                answerInput={answerInput}
                setAnswerInput={setAnswerInput}
                onSubmitAnswer={checkAnswer}
                isChecking={gameState === 'CHECKING'}
            />
            <ResultsTable result={queryResult} />
        </div>
      </div>

      {/* Chat is fixed width on the right, could be collapsible too in future iterations */}
      <ChatAssistant 
        currentCase={currentCase}
        queryHistory={queryHistory}
        onCaseSolved={() => {
            if (!completedCases.includes(currentCase.id)) {
                 setGameState('SOLVED_ANIMATION');
            }
        }}
      />
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { CASES, TABLES } from '../constants';
import { Case } from '../types';
import { 
    IconFolder, 
    IconCheck, 
    IconLock, 
    IconDatabase, 
    IconChevronLeft, 
    IconChevronRight,
    IconSettings,
    IconUser,
    IconSun,
    IconMoon
} from './Icons';

interface SidebarProps {
    currentCase: Case;
    completedCases: string[];
    onCaseSelect: (caseId: string) => void;
    badgeId: string;
    officerName: string; 
    isCollapsed: boolean;
    toggleSidebar: () => void;
    onOpenSettings: () => void;
    theme: 'light' | 'dark';
    toggleTheme: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    currentCase, 
    completedCases, 
    onCaseSelect, 
    badgeId, 
    officerName,
    isCollapsed,
    toggleSidebar,
    onOpenSettings,
    theme,
    toggleTheme
}) => {
    const [difficultyFilter, setDifficultyFilter] = useState<'ALL' | 'Easy' | 'Medium' | 'Hard'>('ALL');

    // Filter the master list based on selection
    const visibleCases = CASES.filter(c => difficultyFilter === 'ALL' || c.difficulty === difficultyFilter);

    // Split into sections
    const academyCases = visibleCases.filter(c => c.id.startsWith('academy'));
    const fieldCases = visibleCases.filter(c => !c.id.startsWith('academy'));

    // Helper to render a case list item
    const CaseItem = ({ c }: { c: Case }) => {
        const index = CASES.findIndex(gameCase => gameCase.id === c.id);
        const isCompleted = completedCases.includes(c.id);
        const isActive = c.id === currentCase.id;
        const isLocked = index > completedCases.length;

        return (
            <button 
                onClick={() => !isLocked && onCaseSelect(c.id)}
                disabled={isLocked}
                title={isCollapsed ? c.title : undefined}
                className={`
                    group w-full flex items-center gap-3 p-2 rounded-lg text-sm transition-all duration-200 relative overflow-hidden
                    ${isActive 
                        ? 'bg-terminal-blue/10 text-terminal-text shadow-[inset_0_0_0_1px_rgba(88,166,255,0.4)]' 
                        : 'text-terminal-text/60 hover:bg-terminal-surface hover:text-terminal-text'}
                    ${isLocked ? 'opacity-40 cursor-not-allowed grayscale' : 'cursor-pointer'}
                `}
            >
                {isActive && (
                    <div className="absolute left-0 top-0 bottom-0 w-[2px] bg-terminal-blue shadow-[0_0_8px_var(--color-terminal-blue)]"></div>
                )}

                <div className={`
                    flex-shrink-0 w-6 h-6 flex items-center justify-center rounded 
                    ${isCompleted && !isActive ? 'text-terminal-green' : ''}
                    ${isActive ? 'text-terminal-blue' : ''}
                    ${!isCompleted && !isActive && !isLocked ? 'text-yellow-500' : ''}
                `}>
                    {isCompleted ? <IconCheck className="w-4 h-4" /> : 
                     isLocked ? <IconLock className="w-3 h-3" /> : 
                     <IconFolder className="w-4 h-4" />}
                </div>

                {!isCollapsed && (
                    <div className="flex-1 text-left truncate flex justify-between items-center">
                        <div className="font-medium truncate pr-2">{c.title}</div>
                        {/* Optional small dot for difficulty if ALL is selected */}
                        {difficultyFilter === 'ALL' && (
                            <div className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${
                                c.difficulty === 'Easy' ? 'bg-green-500/50' : 
                                c.difficulty === 'Medium' ? 'bg-yellow-500/50' : 'bg-red-500/50'
                            }`} title={c.difficulty}></div>
                        )}
                    </div>
                )}
            </button>
        );
    };

    return (
        <div 
            className={`
                relative h-full bg-terminal-bg/95 backdrop-blur-md border-r border-terminal-border flex flex-col transition-all duration-300 ease-in-out z-20 shadow-2xl
                ${isCollapsed ? 'w-16' : 'w-72'}
            `}
        >
            {/* Header / Logo */}
            <div className={`h-16 flex items-center border-b border-terminal-border ${isCollapsed ? 'justify-center' : 'justify-between px-4'}`}>
                {!isCollapsed && (
                    <div className="flex items-center gap-2">
                        <div className="w-2 h-2 bg-terminal-blue rounded-full animate-pulse shadow-[0_0_8px_var(--color-terminal-blue)]"></div>
                        <h1 className="text-lg font-bold text-terminal-text tracking-widest font-sans">SQL-PD</h1>
                    </div>
                )}

                <button 
                    onClick={toggleSidebar}
                    className="p-1.5 rounded-md text-terminal-text/60 hover:bg-terminal-surface hover:text-terminal-text transition-colors"
                >
                    {isCollapsed ? <IconChevronRight className="w-5 h-5" /> : <IconChevronLeft className="w-4 h-4" />}
                </button>
            </div>

            {/* Filter Controls */}
            {!isCollapsed && (
                <div className="px-3 pt-3 flex gap-1 justify-between">
                    {(['ALL', 'Easy', 'Medium', 'Hard'] as const).map((level) => (
                        <button
                            key={level}
                            onClick={() => setDifficultyFilter(level)}
                            className={`
                                flex-1 py-1 text-[10px] uppercase font-bold rounded border transition-all text-center
                                ${difficultyFilter === level
                                    ? 'bg-terminal-blue/10 text-terminal-blue border-terminal-blue/40 shadow-[0_0_10px_rgba(88,166,255,0.1)]'
                                    : 'bg-transparent text-terminal-text/60 border-transparent hover:bg-terminal-surface hover:text-terminal-text'
                                }
                            `}
                        >
                            {level === 'Medium' ? 'Med' : level}
                        </button>
                    ))}
                </div>
            )}

            {/* Content Area */}
            <div className="flex-1 overflow-y-auto overflow-x-hidden scrollbar-thin scrollbar-thumb-terminal-border scrollbar-track-transparent">

                {/* Cases Section */}
                <div className="p-3 space-y-6">
                    {academyCases.length > 0 && (
                        <div>
                            {!isCollapsed && (
                                <h2 className="px-2 text-[10px] uppercase font-bold text-gray-500 tracking-widest mb-2 flex items-center gap-2">
                                    <span className="w-1 h-1 bg-gray-500 rounded-full"></span>
                                    Training
                                </h2>
                            )}
                            <div className="space-y-1">
                                {academyCases.map(c => <CaseItem key={c.id} c={c} />)}
                            </div>
                        </div>
                    )}

                    {fieldCases.length > 0 && (
                        <div>
                            {!isCollapsed && (
                                <h2 className="px-2 text-[10px] uppercase font-bold text-gray-500 tracking-widest mb-2 flex items-center gap-2">
                                    <span className="w-1 h-1 bg-gray-500 rounded-full"></span>
                                    Active Files
                                </h2>
                            )}
                            <div className="space-y-1">
                                {fieldCases.map(c => <CaseItem key={c.id} c={c} />)}
                            </div>
                        </div>
                    )}

                    {academyCases.length === 0 && fieldCases.length === 0 && !isCollapsed && (
                        <div className="text-center text-xs text-terminal-text/50 py-8 italic">
                            No cases match this filter.
                        </div>
                    )}
                </div>

                {/* Schema Section (Only show if not collapsed, or show icon tooltips) */}
                {!isCollapsed && (
                    <div className="p-4 border-t border-terminal-border/50">
                        <h2 className="text-[10px] uppercase font-bold text-gray-500 tracking-widest mb-3 flex items-center gap-2">
                            <IconDatabase className="w-3 h-3" /> Schema
                        </h2>
                        <div className="space-y-1 opacity-80">
                            {TABLES.map(table => (
                                <div key={table.tableName} className="group relative">
                                    <div className="text-xs text-terminal-text/60 font-mono hover:text-terminal-text cursor-help py-1">
                                        {table.tableName}
                                    </div>
                                    {/* Hover Tooltip for Schema */}
                                    <div className="absolute left-0 bottom-full mb-2 w-48 bg-terminal-surface border border-terminal-border p-2 rounded shadow-xl hidden group-hover:block z-50">
                                        <div className="text-[10px] text-terminal-blue font-bold mb-1 border-b border-terminal-border pb-1">COLUMNS</div>
                                        {table.columns.map(col => (
                                            <div key={col.name} className="flex justify-between text-[10px] text-terminal-text/70">
                                                <span>{col.name}</span>
                                                <span className="opacity-50">{col.type}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* Footer / Profile */}
            <div className="p-3 border-t border-terminal-border bg-terminal-surface/20">
                <div className={`flex flex-col gap-2 ${isCollapsed ? 'items-center' : ''}`}>
                    {/* Theme Toggle */}
                    <button 
                        onClick={toggleTheme}
                        className={`
                            flex items-center justify-center p-2 rounded-lg text-terminal-text/60 hover:bg-terminal-surface hover:text-terminal-text transition-colors border border-transparent hover:border-terminal-border
                            ${isCollapsed ? 'w-full' : 'w-full mb-1'}
                        `}
                        title={theme === 'dark' ? "Switch to Light Mode" : "Switch to Dark Mode"}
                    >
                         {theme === 'dark' ? <IconSun className="w-4 h-4" /> : <IconMoon className="w-4 h-4" />}
                         {!isCollapsed && <span className="text-xs ml-2 font-medium">Switch Theme</span>}
                    </button>

                    <button 
                        onClick={onOpenSettings}
                        className={`
                            w-full flex items-center rounded-lg p-2 transition-all hover:bg-terminal-surface border border-transparent hover:border-terminal-border
                            ${isCollapsed ? 'justify-center' : 'justify-between'}
                        `}
                    >
                        <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded bg-gradient-to-tr from-gray-800 to-gray-700 flex items-center justify-center border border-gray-600 shadow-lg">
                                <IconUser className="w-4 h-4 text-gray-300" />
                            </div>
                            {!isCollapsed && (
                                <div className="text-left w-24">
                                    <div className="text-xs font-bold text-terminal-text truncate">{officerName}</div>
                                    <div className="text-[10px] text-terminal-green font-mono">#{badgeId}</div>
                                </div>
                            )}
                        </div>
                        {!isCollapsed && <IconSettings className="w-4 h-4 text-terminal-text/50" />}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default Sidebar;

import React from 'react';

interface SqlEditorProps {
    sql: string;
    onChange: (val: string) => void;
    onRun: (sql: string) => void;
    isRunning: boolean;
    answerInput: string;
    setAnswerInput: (val: string) => void;
    onSubmitAnswer: () => void;
    isChecking: boolean;
}

const SqlEditor: React.FC<SqlEditorProps> = ({ 
    sql,
    onChange,
    onRun, 
    isRunning, 
    answerInput, 
    setAnswerInput, 
    onSubmitAnswer,
    isChecking
}) => {

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            onRun(sql);
        }
    };

    return (
        <div className="flex flex-col h-1/2 min-h-[300px] border-b border-terminal-border">
            <div className="bg-terminal-border/20 px-4 py-2 flex justify-between items-center border-b border-terminal-border transition-colors">
                <span className="text-xs uppercase text-terminal-text font-bold tracking-widest">Query Console</span>
                <span className="text-xs text-terminal-text opacity-50">CTRL+ENTER to run</span>
            </div>
            <textarea
                value={sql}
                onChange={(e) => onChange(e.target.value)}
                onKeyDown={handleKeyDown}
                className="flex-1 bg-terminal-bg text-terminal-text p-4 font-mono text-base resize-none focus:outline-none focus:ring-1 focus:ring-terminal-border transition-colors placeholder:text-terminal-text/30"
                placeholder="-- Type your SQL query here...
SELECT * FROM crime_scene_report LIMIT 5;"
                spellCheck={false}
            />
            <div className="p-3 bg-terminal-bg border-t border-terminal-border flex justify-between items-center gap-4 transition-colors">
                {/* Answer Section */}
                <div className="flex-1 flex items-center gap-2">
                    <input 
                        type="text" 
                        value={answerInput}
                        onChange={(e) => setAnswerInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && onSubmitAnswer()}
                        placeholder="Type Final Answer (e.g. ID or Name)"
                        className="flex-1 bg-terminal-border/20 border border-terminal-border rounded px-3 py-2 text-sm text-terminal-green focus:outline-none focus:border-terminal-green font-mono placeholder:text-terminal-text/30 transition-colors"
                    />
                    <button 
                        onClick={onSubmitAnswer}
                        disabled={isChecking || !answerInput.trim()}
                        className={`
                            px-4 py-2 bg-terminal-blue/10 text-terminal-blue border border-terminal-blue/50 font-bold font-mono text-sm rounded hover:bg-terminal-blue/20 transition-colors
                            ${(isChecking || !answerInput.trim()) ? 'opacity-50 cursor-not-allowed' : ''}
                        `}
                    >
                        {isChecking ? 'VERIFYING...' : 'SUBMIT'}
                    </button>
                </div>

                <div className="h-6 w-px bg-terminal-border"></div>

                {/* Run Query Section */}
                <button 
                    onClick={() => onRun(sql)}
                    disabled={isRunning}
                    className={`
                        px-6 py-2 bg-terminal-green text-black font-bold font-mono text-sm rounded hover:bg-terminal-green/80 transition-colors
                        ${isRunning ? 'opacity-50 cursor-not-allowed' : ''}
                    `}
                >
                    {isRunning ? 'EXECUTING...' : 'RUN QUERY'}
                </button>
            </div>
        </div>
    );
};

export default SqlEditor;

import React from 'react';
import { QueryResult } from '../types';

interface ResultsTableProps {
    result: QueryResult | null;
}

const ResultsTable: React.FC<ResultsTableProps> = ({ result }) => {
    if (!result) {
        return (
            <div className="h-1/2 flex items-center justify-center text-terminal-text opacity-30 font-mono bg-terminal-bg transition-colors">
                NO RESULTS TO DISPLAY
            </div>
        );
    }

    if (result.error) {
        return (
            <div className="h-1/2 p-4 font-mono bg-terminal-bg transition-colors">
                <div className="text-red-500 font-bold mb-2">ERROR:</div>
                <div className="text-red-400">{result.error}</div>
            </div>
        );
    }

    if (result.data.length === 0 && result.columns.length === 0) {
        return (
             <div className="h-1/2 p-4 font-mono text-terminal-green bg-terminal-bg transition-colors">
                Query executed successfully. No rows returned.
                <div className="text-xs opacity-50 mt-1">{result.executionTime?.toFixed(2)}ms</div>
            </div>
        );
    }

    return (
        <div className="h-1/2 overflow-auto bg-terminal-bg flex flex-col transition-colors">
            <div className="px-4 py-2 bg-terminal-border/20 border-b border-terminal-border flex justify-between items-center sticky top-0">
                <span className="text-xs uppercase text-terminal-text font-bold tracking-widest">
                    Result Grid ({result.data.length} rows)
                </span>
                <span className="text-xs font-mono text-terminal-text opacity-50">
                    {result.executionTime?.toFixed(2)}ms
                </span>
            </div>
            <div className="flex-1 overflow-auto">
                <table className="w-full text-left border-collapse font-mono text-sm">
                    <thead className="sticky top-0 bg-terminal-bg z-10">
                        <tr>
                            {result.columns.map((col, idx) => (
                                <th key={idx} className="p-3 border-b border-terminal-border text-terminal-blue font-bold whitespace-nowrap bg-terminal-bg">
                                    {col}
                                </th>
                            ))}
                        </tr>
                    </thead>
                    <tbody>
                        {result.data.map((row, rowIdx) => (
                            <tr key={rowIdx} className="hover:bg-terminal-border/10 transition-colors group">
                                {result.columns.map((col, colIdx) => (
                                    <td key={colIdx} className="p-3 border-b border-terminal-border/50 text-terminal-text whitespace-nowrap max-w-xs overflow-hidden text-ellipsis">
                                        {row[col] === null ? <span className="text-red-900 dark:text-red-300 italic">NULL</span> : String(row[col])}
                                    </td>
                                ))}
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default ResultsTable;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage, Case } from '../types';
import { getFastHint, getKnowledgeHelp, submitCaseReview } from '../services/geminiService';

interface ChatAssistantProps {
    currentCase: Case;
    queryHistory: string[];
    onCaseSolved: () => void;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentCase, queryHistory, onCaseSolved }) => {
    const [messages, setMessages] = useState<ChatMessage[]>([
        { id: '1', role: 'model', text: `Detective, I'm your AI partner. I can help with SQL syntax or give you clues. Type "solve: [name]" to submit a suspect.`, timestamp: Date.now() }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(scrollToBottom, [messages]);

    const handleSend = async () => {
        if (!input.trim() || isLoading) return;

        const userMsg: ChatMessage = {
            id: Date.now().toString(),
            role: 'user',
            text: input,
            timestamp: Date.now()
        };

        setMessages(prev => [...prev, userMsg]);
        setInput('');
        setIsLoading(true);

        try {
            // Determine intent
            const lowerInput = input.toLowerCase();
            let aiResponseText = '';

            if (lowerInput.startsWith('solve:')) {
                // SUBMIT ANSWER -> GEMINI 3 PRO (Thinking)
                const answer = input.substring(6).trim();

                // Add a placeholder for thinking
                setMessages(prev => [...prev, {
                    id: 'thinking',
                    role: 'model',
                    text: "Analyzing case files and cross-referencing evidence...",
                    timestamp: Date.now(),
                    isThinking: true
                }]);

                const review = await submitCaseReview(
                    JSON.stringify(currentCase),
                    answer,
                    queryHistory
                );

                // Check simple exact match for game logic trigger, but let AI explain it
                const isCorrect = answer.toLowerCase() === currentCase.expectedAnswer.toLowerCase();

                setMessages(prev => prev.filter(m => m.id !== 'thinking')); // Remove thinking placeholder

                aiResponseText = review;

                if (isCorrect) {
                     // Wait a bit then trigger solved
                     setTimeout(onCaseSolved, 3000);
                }

            } else if (lowerInput.includes('how to') || lowerInput.includes('syntax') || lowerInput.includes('what is')) {
                // SQL HELP -> GEMINI 3 FLASH (Search Grounding)
                const { text, sources } = await getKnowledgeHelp(input);
                aiResponseText = text;
                if (sources.length > 0) {
                    aiResponseText += `\n\nSources:\n${sources.map(s => `- ${s}`).join('\n')}`;
                }

            } else if (lowerInput.includes('hint')) {
                // STATIC HINT + AI FLAVOR
                if (currentCase.hint) {
                    aiResponseText = `I found a note in the case file that might help:\n\n"${currentCase.hint}"`;
                } else {
                    const hint = await getFastHint(input, currentCase.briefing);
                    aiResponseText = hint;
                }
            } else {
                // HINT -> GEMINI 2.5 FLASH LITE (Fast)
                const hint = await getFastHint(input, currentCase.briefing);
                aiResponseText = hint;
            }

            const aiMsg: ChatMessage = {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: aiResponseText,
                timestamp: Date.now()
            };
            setMessages(prev => [...prev, aiMsg]);

        } catch (error) {
            setMessages(prev => [...prev, {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: "Communication error. Try again.",
                timestamp: Date.now()
            }]);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex flex-col h-full bg-terminal-bg border-l border-terminal-border w-96 transition-colors">
            <div className="p-4 border-b border-terminal-border bg-terminal-surface/30">
                <h2 className="text-terminal-blue font-bold uppercase text-xs tracking-widest">AI Field Partner</h2>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                        <div 
                            className={`
                                max-w-[90%] p-3 rounded-lg text-sm font-mono whitespace-pre-wrap shadow-sm
                                ${msg.role === 'user' 
                                    ? 'bg-terminal-blue/10 text-terminal-blue border border-terminal-blue/30 rounded-br-none' 
                                    : 'bg-terminal-surface text-terminal-text border border-terminal-border rounded-bl-none'}
                                ${msg.isThinking ? 'animate-pulse' : ''}
                            `}
                        >
                            {msg.text}
                        </div>
                    </div>
                ))}
                <div ref={messagesEndRef} />
            </div>

            <div className="p-4 border-t border-terminal-border bg-terminal-surface/30">
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        placeholder="Ask for hint or 'solve: [name]'"
                        className="flex-1 bg-terminal-bg border border-terminal-border rounded px-3 py-2 text-sm text-terminal-text focus:outline-none focus:border-terminal-blue font-mono transition-colors"
                        disabled={isLoading}
                    />
                    <button 
                        onClick={handleSend}
                        disabled={isLoading}
                        className="p-2 bg-terminal-blue/10 text-terminal-blue border border-terminal-blue/30 rounded hover:bg-terminal-blue/20 disabled:opacity-50 transition-colors"
                    >
                        ➤
                    </button>
                </div>
            </div>
        </div>
    );
};

export default ChatAssistant;

